window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["s"]={"Stanisław": "<b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Szymon": "<b>Szymon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i><b>שמעון</b></i> <i>Szim’on</i>, lub <i><b>שִׁמְעוֹן</b></i> <i>Szime’on</i>, „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> wysłuchał”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, biblijnego. Początkowo stosowana w polskich przekładach Biblii forma tego imienia <b>Symeon</b> to rzadziej dziś używana forma, bardziej rozpowszechniona na Wschodzie. Niektórzy autorzy uznają imię za greckie, widząc w nim bądź tylko zhellenizowaną formę semickiego Szimeon, bądź rzeczywiste imię pochodzenia greckiego. W <a href=\"https://pl.wikipedia.org/wiki/Hagiografia\" target=\"_blank\" rel=\"noopener noreferrer\">hagiografii</a> istnieje podział na świętych o imieniu <b>Szymon</b> i <b>Symeon</b> będącego oboczną formą pierwszego imienia.", "Sebastian": "<b>Sebastian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;σεβαστός oznaczającego „czcigodny, dostojny”. Odpowiada łacińskiemu <i><a href=\"https://pl.wikipedia.org/wiki/August_(tytu%C5%82)\" target=\"_blank\" rel=\"noopener noreferrer\">Augustus</a></i>. Chrześcijańskim patronem tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sebastian\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian, męczennik rzymski</a>.", "Sławomir": "<b>Sławomir</b>, <b>Sławimir</b>, <b>Sławomier</b>, <b>Sławmir</b> – staropolskie męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów <i>Sławo-</i> („sława, sławić”) i <i>-mir</i> („pokój, spokój, dobro, świat”). Imię to prawdopodobnie znaczyło tyle, co „ten, który zdobywa sławę poprzez pokój, pokojowe zachowanie, zaprowadzanie porządku, spokoju” (w przeciwieństwie do imion typu <a href=\"https://pl.wikipedia.org/wiki/Borzys%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Borzysław</a>, w których sława zdobywana jest w walce).", "Stefan": "<b>Stefan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Στέφανος, <i>Stefanos</i>). Wywodzi się od słowa oznaczającego znak zwycięstwa – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;στέφανος oznacza „wieniec”. Pierwotnym polskim odpowiednikiem było imię <a href=\"https://pl.wikipedia.org/wiki/Szczepan\" target=\"_blank\" rel=\"noopener noreferrer\">Szczepan</a>.", "Sylwester": "<b>Sylwester</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>silvestris</em> oznaczającego „żyjący w lesie”, „dziki”. Poświadczone w Polsce od 1220 roku. Dawniej uważano, że imię <a href=\"https://pl.wikipedia.org/wiki/Lasota_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Lasota</a> powstało jako odpowiednik znaczeniowy Sylwestra, jednak Lasota jest poświadczony na ziemiach polskich w dokumentach wcześniej i był szerzej nadawany. Odnotowano dziesięciu świętych Sylwestrów, patronów tego imienia.", "Szczepan": "<b>Szczepan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Pierwotna spolonizowana forma greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>, przejęta do polszczyzny w czasach najdawniejszych, jeszcze przed ustaleniem się w języku polskim spółgłoski <i><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_wargowo-z%C4%99bowa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">f</a></i> – która była wówczas zastępowana przez <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dwuwargowa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">[p]</a> lub <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dwuwargowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">[b]</a> (tę drugą w zapożyczeniach niemieckich lub w wyrazach przejętych za niemieckim pośrednictwem) – w brzmieniu <b>Szczepan</b> i dopiero wtórnie sprowadzona do języka polskiego w brzmieniu <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>.", "Seweryn": "<b>Seweryn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. <i>Severus</i> oznacza „surowy, srogi, poważny”. Wśród imion nadawanych nowo narodzonym dzieciom, Seweryn w 2017 r. zajmował 106. miejsce w grupie imion męskich.", "Samuel": "<b>Samuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Šmū'el</i>, oznaczającego „<i>uproszony od Boga</i>”, „<i>wyproszony od Boga</i>”, „<i>Bóg wysłuchał</i>”, „<i>imię Boga</i>” lub „<i>jego imię to Bóg</i>”. W Polsce imię to jest poświadczone od 1401 roku, a w XVII wieku należało do najpopularniejszych imion szlacheckich. Nosił je ostatni z sędziów izraelskich oraz pięciu innych świętych katolickich.", "Sergiusz": "<b>Sergiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pierwotne nomen gentilicium (nazwisko rodowe) <i>Sergius</i> (gens Sergia). Ród Sergia był starym rodem patrycjuszowskim. Pochodzenie nazwy rodu nie zostało jednoznacznie wyjaśnione. Nie można wykluczyć źródła etruskiego, jak przy wielu nazwach rodów rzymskich.", "Serafin": "<b>Serafin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> słowa oznaczającego \"płomienny\". Nazwa często spotykana w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>.", "Sean": "<b>Jan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἰωάννης od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> rdzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;יחנ&#8206; – łaska) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajsku</a> יוחנן (<i>Johanan</i>) oznacza „Jahwe jest łaskawy”. Według <a href=\"https://pl.wikipedia.org/wiki/Ewangelia\" target=\"_blank\" rel=\"noopener noreferrer\">Ewangelii</a> imię to nosił <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Chrzciciel</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostoł</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Ewangelista\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Ewangelista</a>. Zostało ono przejęte najpierw do greki, a potem do łaciny. Rozpowszechniło się we wszystkich krajach <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskich</a>.", "Szczęsny": "<b>Szczęsny</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a>, po raz pierwszy notowane w <a href=\"https://pl.wikipedia.org/wiki/1422\" target=\"_blank\" rel=\"noopener noreferrer\">1422</a> roku. Wywodzi się od słowa „szczęśliwy” i jest uważane za odpowiednik znaczeniowy <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Feliks\" target=\"_blank\" rel=\"noopener noreferrer\">Feliks</a> i greckiego <a href=\"https://pl.wikipedia.org/wiki/Makary\" target=\"_blank\" rel=\"noopener noreferrer\">Makary</a>. Patronem tego imienia jest święty <a href=\"https://pl.wikipedia.org/wiki/Zygmunt_Szcz%C4%99sny_Feli%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Zygmunt Szczęsny Feliński</a>, wspominany <a href=\"https://pl.wikipedia.org/wiki/17_wrze%C5%9Bnia\" target=\"_blank\" rel=\"noopener noreferrer\">17 września</a>.", "Sambor": "<b>Sambor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie, złożone z członów <i>Sam-</i> („samotny”) oraz <i>-bor</i> („walczyć, zmagać się”). Mogło oznaczać „walczącego samotnie”.", "Sylweriusz": "<b>Sylweriusz</b>, <b>Sylwery</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, którego patronem jest <a href=\"https://pl.wikipedia.org/wiki/Sylweriusz_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">papież Sylweriusz</a>.", "Sobiesław": "Imię <i>Sobiesław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poganie\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członu <i>Sobie-</i> i <i>-sław</i> („sława”). Oznacza „zachowujący sławę dla siebie” lub „zapracowujący na sławę dla siebie”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Sven": "<b>Swen</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a> <i>sveinn</i> – „młody mężczyzna”. Imię to pojawiło się również w Polsce. W 1994 roku w Polsce żyło 6 osób o tym imieniu; najstarsza z nich urodzona w <a href=\"https://pl.wikipedia.org/wiki/Lata_60._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">latach 60.</a>.", "Sylwiusz": "Imię pochodzenia łacińskiego od słowa silvio oznaczającego: leśny, dziki, żyjący w lesie.", "Saba": "<b>Sabbas, Sabas, Saba</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a>, od <i>saba</i> – „starzec, dziad, dziadek”. Jego patronem jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sawa\" target=\"_blank\" rel=\"noopener noreferrer\">święty Saba (Sawa)</a>, najważniejszy święty w <a href=\"https://pl.wikipedia.org/wiki/Serbski_Ko%C5%9Bci%C3%B3%C5%82_Prawos%C5%82awny\" target=\"_blank\" rel=\"noopener noreferrer\">Serbskiej Cerkwi</a>, a także inni święci, również katoliccy, w liczbie co najmniej piętnastu. <i><b>Sawa</b></i> zaś jest nowogrecką formą imienia, występującą na obszarze chrześcijaństwa prawosławnego, od której być może pochodzą m.in. takie nazwiska, jak Sawa, Sawka, Sawczyn, <a href=\"https://pl.wikipedia.org/wiki/Sawiccy\" target=\"_blank\" rel=\"noopener noreferrer\">Sawicki</a>.", "Saturnin": "<b>Saturnin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia boga rolnictwa <a href=\"https://pl.wikipedia.org/wiki/Saturn_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Saturna</a>. Wśród patronów – <a href=\"https://pl.wikipedia.org/wiki/Saturnin_z_Tuluzy\" target=\"_blank\" rel=\"noopener noreferrer\">św. Saturnin</a>, męczennik (<a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wiek</a>) i inni liczni święci.", "Siergiej": "<b>Sergiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pierwotne nomen gentilicium (nazwisko rodowe) <i>Sergius</i> (gens Sergia). Ród Sergia był starym rodem patrycjuszowskim. Pochodzenie nazwy rodu nie zostało jednoznacznie wyjaśnione. Nie można wykluczyć źródła etruskiego, jak przy wielu nazwach rodów rzymskich.", "Symeon": "<b>Szymon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i><b>שמעון</b></i> <i>Szim’on</i>, lub <i><b>שִׁמְעוֹן</b></i> <i>Szime’on</i>, „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> wysłuchał”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, biblijnego. Początkowo stosowana w polskich przekładach Biblii forma tego imienia <b>Symeon</b> to rzadziej dziś używana forma, bardziej rozpowszechniona na Wschodzie. Niektórzy autorzy uznają imię za greckie, widząc w nim bądź tylko zhellenizowaną formę semickiego Szimeon, bądź rzeczywiste imię pochodzenia greckiego. W <a href=\"https://pl.wikipedia.org/wiki/Hagiografia\" target=\"_blank\" rel=\"noopener noreferrer\">hagiografii</a> istnieje podział na świętych o imieniu <b>Szymon</b> i <b>Symeon</b> będącego oboczną formą pierwszego imienia.", "Samson": "<b>Samson</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> Szimszon, שִׁמְשׁוֹן, co pochodzi od słowa <i>szemesz</i> – „słońce”, lub <i>szamen</i> – „silny”, „siłacz”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> شمشون, wym. Szamszun) – ostatni z Sędziów opisanych w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">starotestamentowej</a> <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_S%C4%99dzi%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\"><i>Księdze Sędziów</i></a> r. 13-16. Trzeci zaś licząc od końca dla <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">starożytnego Izraela</a>; po nim sędziami byli <a href=\"https://pl.wikipedia.org/wiki/Heli\" target=\"_blank\" rel=\"noopener noreferrer\">Heli</a> i <a href=\"https://pl.wikipedia.org/wiki/Samuel_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Samuel</a>. W przeciwieństwie do wielu postaci opisanych w Starym Testamencie, nie jest wymieniony w <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranie</a>. Jako jedyny sędzia w Księdze Sędziów wybrany przez Boga przed narodzeniem do roli, którą miał spełnić i to bez wcześniejszych próśb ludu o ratunek. Jego wyjątkowość poświadcza zrodzenie z niepłodnej (jak <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaak</a>, Samuel czy <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Chrzciciel</a>). Był obdarzony nadludzką siłą, którą wykorzystywał do walki z wrogami Izraela – <a href=\"https://pl.wikipedia.org/wiki/Filistyni\" target=\"_blank\" rel=\"noopener noreferrer\">Filistynami</a>. Dokonywał czynów niemożliwych dla zwykłych ludzi: zabił lwa gołymi rękami, pokonał armię wroga oślą szczęką i siłą własnych mięśni, wyrwał bramę miasta wraz z odrzwiami, zburzył budynek. Był <a href=\"https://pl.wikipedia.org/wiki/Nazireat\" target=\"_blank\" rel=\"noopener noreferrer\">nazirejczykiem</a> – jednak nie z własnego wyboru – ale z powziętego przed jego narodzeniem suwerennego postanowienia Boga.", "Selim": "<b>Selim</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Turcy\" target=\"_blank\" rel=\"noopener noreferrer\">tureckiego</a>, pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Imiona_arabskie\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> imienia Salim, co oznacza „bezpieczny”.", "Sławoj": "<b>Sławoj</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, nienotowane w dawnych dokumentach i stanowiące najprawdopodobniej XIX-wieczny <a href=\"https://pl.wikipedia.org/wiki/Neologizm\" target=\"_blank\" rel=\"noopener noreferrer\">neologizm</a> stworzony na wzór dwuczłonowych <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a>. Istniało natomiast staropolskie imię złożone z tych samych dwóch członów w zmienionej kolejności: <a href=\"https://pl.wikipedia.org/wiki/Wojs%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Wojsław</a>.", "Salomon": "<b>Salomon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> imienia שְׁלֹמֹה<i> (Shelomo)</i> należącego do słynnego z mądrości króla <a href=\"https://pl.wikipedia.org/wiki/Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">Izraela</a> – <a href=\"https://pl.wikipedia.org/wiki/Salomon_(kr%C3%B3l_Izraela)\" target=\"_blank\" rel=\"noopener noreferrer\">Salomona</a>. Istnieje kilku świętych katolickich o tym imieniu.", "Sławosz": "<b>Sławosz</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię słowiańskie</a>. Zdrobniona forma dwuczłonowych imion typu <a href=\"https://pl.wikipedia.org/wiki/S%C5%82awomir\" target=\"_blank\" rel=\"noopener noreferrer\">Sławomir</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82awos%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Sławosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Miros%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Mirosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Dziwis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Dziwisław</a> z członem <i>Sław-</i> albo <i>-sław</i>. Również imię używane samodzielnie o znaczeniu „sławny, znakomity, godny chwały”.", "Salah": "Odmawiający salat powinien być w stanie rytualnej czystości (uzyskuje się ją przez obmycie wodą – <a href=\"https://pl.wikipedia.org/wiki/Wudu_(ablucja)\" target=\"_blank\" rel=\"noopener noreferrer\">wudu</a>, a gdy jej nie ma, to piaskiem – <a href=\"https://pl.wikipedia.org/wiki/Tajammum\" target=\"_blank\" rel=\"noopener noreferrer\">tajammum</a>). Rozkłada on specjalny dywanik (<i><a href=\"https://pl.wikipedia.org/wiki/Modlitewnik_(islam)\" target=\"_blank\" rel=\"noopener noreferrer\">sadżadża</a></i>; nie jest obowiązkowy), zwraca się w kierunku <a href=\"https://pl.wikipedia.org/wiki/Mekka\" target=\"_blank\" rel=\"noopener noreferrer\">Mekki</a> i wykonuje określoną liczbę pokłonów, gestów i recytacji wersetów (<a href=\"https://pl.wikipedia.org/wiki/Aja\" target=\"_blank\" rel=\"noopener noreferrer\">ajatów</a>) <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranu</a> (przede wszystkim pierwszej sury <i><a href=\"https://pl.wikipedia.org/wiki/Al-Fatiha\" target=\"_blank\" rel=\"noopener noreferrer\">Al-Fatiha</a></i>). Największe znaczenie mają modlitwy piątkowe (<a href=\"https://pl.wikipedia.org/wiki/D%C5%BCummuah\" target=\"_blank\" rel=\"noopener noreferrer\">Dżummuah</a>) – odmawiane wspólnie w <a href=\"https://pl.wikipedia.org/wiki/Meczet\" target=\"_blank\" rel=\"noopener noreferrer\">meczecie</a>, którym często towarzyszy kazanie (<i><a href=\"https://pl.wikipedia.org/wiki/Chutba\" target=\"_blank\" rel=\"noopener noreferrer\">chutba</a></i>). Salat na całym świecie odbywa się wyłącznie w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">języku arabskim</a>.", "Salman": "Salman (również jako Salmaan lub Selman, arab. سلمان) popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> oznaczające <i>błogosławiony</i>, także <i>pokój</i>.", "Saul": "<b>Szaweł</b>, Saul – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (&#8207;שָׁאוּל&#8206; <i>šā’ūl</i> „uproszony, pożądany”).", "Sylwin": "<b>Sylwin</b> – <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, utworzone od męskiego <a href=\"https://pl.wikipedia.org/wiki/Sylwiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwiusz</a> przy pomocy <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-inus</i>, który wskazywał na pochodzenie od kogoś lub zdrabniał. W Kościele katolickim istniało czterech świętych o tym imieniu. <b>Sylwin</b> nadawany jest w Polsce co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1847\" target=\"_blank\" rel=\"noopener noreferrer\">1847</a> roku.", "Sabir": "<b>Lingua franca</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a> „język Franków”) – w szerokim znaczeniu: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_(mowa)\" target=\"_blank\" rel=\"noopener noreferrer\">język</a> o charakterze międzynarodowym lub międzygrupowym, używany jako środek porozumiewania się na obszarach wielojęzycznych i między osobami niemającymi wspólnego języka ojczystego.", "Serwacy": "<b>Serwacy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „ten, który został zbawiony”.", "Sabin": "<b>Sabin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>sabinus</i> oznaczającego pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Sabinowie\" target=\"_blank\" rel=\"noopener noreferrer\">Sabinów</a>, plemienia zamieszkującego środkową <a href=\"https://pl.wikipedia.org/wiki/Italia_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Italię</a>. Wśród patronów św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Sabin_ze_Spoleto\" target=\"_blank\" rel=\"noopener noreferrer\">Sabin ze Spoleto</a>, biskup i męczennik (†303).", "Ścibor": "<b>Czścibor</b>, <b>Ścibor</b>, <b>Czcibor</b>, <b>Cibor</b>, <b>Czesbor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Znaczenie imienia: „walczący o cześć”, „obrońca czci”, lub „czczący walkę”. Od członów „czci-” (daw. „czści-”), „czcij”, od czcić (daw. czścić, porównaj cześć) oraz „bor-” – od daw. „borzyć” „walczyć” (porównaj „borykać się”).", "Shahid": "<b>Szahid</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;شَهيد&#8206;, <i>šahīd</i>, „świadek, męczennik”) − termin wywodzący się z <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranu</a>, oznaczający osobę, która oddaje swoje życie w sprawie wiary, za co ma obiecaną nagrodę wieczną, czyli życie w raju (<a href=\"https://pl.wikipedia.org/wiki/D%C5%BCanna\" target=\"_blank\" rel=\"noopener noreferrer\">dżanna</a>).", "Sharon": "<b>Szaron</b>, <b>Sharon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׁרוֹן) – hebrajskie imię stosowane dla obu płci, które oznacza dosłownie <i>żyzną równinę</i>.", "Siemowit": "<b>Siemowit</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Siemo-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*sěmьja</i> ma m.in. znaczenia „rodzina, ród; czeladź, służba, własność”) i <i>-wit</i> („pan, władca”, por. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*vitъ</i> – „pan, możny”). Imię to wyrażało życzenie, aby nim obdarzony przewodził swojej wspólnocie. Spopularyzowało się ono w czasach nowszych w zniekształconej formie jako <a href=\"https://pl.wikipedia.org/wiki/Ziemowit_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Ziemowit</a>. <b>Siemowit</b> był imieniem charakterystycznym dla <a href=\"https://pl.wikipedia.org/wiki/Piastowie\" target=\"_blank\" rel=\"noopener noreferrer\">dynastii piastowskiej</a> i występował wśród <a href=\"https://pl.wikipedia.org/wiki/Piastowie_mazowieccy\" target=\"_blank\" rel=\"noopener noreferrer\">Piastów mazowieckich</a> do <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a>.", "Sewer": "<b>Sewer</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Przymiotnik\" target=\"_blank\" rel=\"noopener noreferrer\">przymiotnika</a> <i>severus</i>, 'surowy, poważny'. Należało w <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">starożytnym Rzymie</a> do popularniejszych <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">cognominów</a> (przydomków). W latach 193-235 w Rzymie panowała dynastia <a href=\"https://pl.wikipedia.org/wiki/Sewerowie\" target=\"_blank\" rel=\"noopener noreferrer\">Sewerów</a>, do której należeli m.in. <a href=\"https://pl.wikipedia.org/wiki/Septymiusz_Sewer\" target=\"_blank\" rel=\"noopener noreferrer\">Septymiusz Sewer</a>, <a href=\"https://pl.wikipedia.org/wiki/Karakalla\" target=\"_blank\" rel=\"noopener noreferrer\">Karakalla</a>, <a href=\"https://pl.wikipedia.org/wiki/Heliogabal_(cesarz_rzymski)\" target=\"_blank\" rel=\"noopener noreferrer\">Heliogabal</a>, <a href=\"https://pl.wikipedia.org/wiki/Aleksander_Sewer\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksander Sewer</a>. Od niego zostało następnie utworzone imię <a href=\"https://pl.wikipedia.org/wiki/Seweryn\" target=\"_blank\" rel=\"noopener noreferrer\">Seweryn</a>.", "Sykstus": "<b>Sykstus</b>, Sykst – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie przejęte poprzez <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacinę</a> z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greki</a>, pochodzące od greckiego imienia Ksustos (<i>ksustós</i> - „wygładzony, elegancki”), w którym przez analogię do łacińskiego imienia <i>Sextus</i> (Sekstus – „szósty”) doszło do przestawienia głosek. Imię to było nadawane w Polsce od średniowiecza, poświadczone w formie pochodnej Syksta (m.) oraz w <a href=\"https://pl.wikipedia.org/wiki/1265\" target=\"_blank\" rel=\"noopener noreferrer\">1265</a> roku w łac. formie <i>Sixtus</i>; możliwe staropolskie zdrobnienia: Syc, Syc(z)ek, Syc(z)ko, Sych, Sychno, Sychta, Sysz, Syszek, Syszka, Syszko. Istnieje pięciu świętych katolickich o tym imieniu.", "Szarbel": "<b>Sarbeliusz</b>, <b>Sarbel</b>, <b>Szarbel</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, odnoszące się do człowieka noszącego szerokie spodnie, a więc <a href=\"https://pl.wikipedia.org/wiki/Scyci\" target=\"_blank\" rel=\"noopener noreferrer\">Scyty</a> lub <a href=\"https://pl.wikipedia.org/wiki/Asyryjczycy\" target=\"_blank\" rel=\"noopener noreferrer\">Asyryjczyka</a>. Podstawę imienia stanowi <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskie</a> słowo <i>sarbalin</i> oznaczającego <a href=\"https://pl.wikipedia.org/wiki/Szarawary\" target=\"_blank\" rel=\"noopener noreferrer\">szarawary</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">pers.</a> <i>szalwār</i> ‘spodnie’).", "Świętosław": "<b>Świętosław</b>, <b>Święcesław</b>, <b>Święcsław</b>, <b>Święsław</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorw.</a> <i>Svjetoslav</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a> <i>Svetoslav</i>) – starosłowiańskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Złożone jest z członów: <i>Święto-</i> („święty”, „silny, mocny”) i <i>-sław</i> („sława”) i oznacza człowieka cieszącego się mocną sławą. W materiałach źródłowych występuje od XII wieku. Do końca <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a> imię to zanotowano u około 1000 osób.", "Szabolcs": "<b>Szabolcs</b> – węgierskie imię męskie, noszą je np. <a href=\"https://pl.wikipedia.org/wiki/Szabolcs_Huszti\" target=\"_blank\" rel=\"noopener noreferrer\">Szabolcs Huszti</a>, <a href=\"https://pl.wikipedia.org/wiki/Szabolcs_Fazakas\" target=\"_blank\" rel=\"noopener noreferrer\">Szabolcs Fazakas</a>, <a href=\"https://pl.wikipedia.org/wiki/Szabolcs_Balajcza\" target=\"_blank\" rel=\"noopener noreferrer\">Szabolcs Balajcza</a>. Tak nazywał się, według <a href=\"https://pl.wikipedia.org/wiki/Simon_K%C3%A9zai\" target=\"_blank\" rel=\"noopener noreferrer\">Simona Kézaia</a> jeden z <a href=\"https://pl.wikipedia.org/wiki/Siedmiu_w%C4%99gierskich_wodz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">siedmiu węgierskich wodzów</a> – Szabolcs (osoba).", "Slobodan": "We wczesnej serbskiej literaturze imię Slobodan było używane jako zamiennik (odpowiednik znaczeniowy) <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> <a href=\"https://pl.wikipedia.org/wiki/Eleuteriusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Eleuterego</a>, które pochodziło od Ελευθεριος „wolny, niezależny” (podobnie jak w Polsce za odpowiednik znaczeniowy łacińskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Ignacy\" target=\"_blank\" rel=\"noopener noreferrer\">Ignacy</a> od <i>ignis</i> „ogień” traktowano <a href=\"https://pl.wikipedia.org/wiki/%C5%BBegota_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Żegotę</a>, od <i>żec</i> „palić”, od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*žekti</i>, <i>*žьgǫ</i>). U południowych Słowian imię wskrzesił i na nowo spopularyzował <a href=\"https://pl.wikipedia.org/wiki/Vladimir_Jovanovi%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">Vladimir Jovanović</a> (1833-1922), <a href=\"https://pl.wikipedia.org/wiki/Serbowie\" target=\"_blank\" rel=\"noopener noreferrer\">serbski</a> <a href=\"https://pl.wikipedia.org/wiki/Liberalizm\" target=\"_blank\" rel=\"noopener noreferrer\">liberalny</a> myśliciel, który swoim dzieciom dał na imię, synowi Slobodan w 1869 r. i córce Pravda w 1871 r.", "Sahib": "<b>Sahib</b> (z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> „pan, władca”) – forma honoryfikacyjna używana w językach indyjskich.", "Smith": "<b>Smith</b> – <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a> angielskiego pochodzenia. Pochodzi od staroangielskiego słowa <i>smið</i> oznaczającego <a href=\"https://pl.wikipedia.org/wiki/Kowal\" target=\"_blank\" rel=\"noopener noreferrer\">kowala</a>. Jest to jedno z najbardziej popularnych nazwisk na świecie. W <a href=\"https://pl.wikipedia.org/wiki/Wielka_Brytania\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkiej Brytanii</a> i <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">Stanach Zjednoczonych</a> posługuje się nim ponad jeden procent ludności, w tym w samych Stanach Zjednoczonych ponad 2,5 miliona ludzi.", "Soren": "<b>Seweryn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. <i>Severus</i> oznacza „surowy, srogi, poważny”. Wśród imion nadawanych nowo narodzonym dzieciom, Seweryn w 2017 r. zajmował 106. miejsce w grupie imion męskich.", "Søren": "<b>Seweryn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. <i>Severus</i> oznacza „surowy, srogi, poważny”. Wśród imion nadawanych nowo narodzonym dzieciom, Seweryn w 2017 r. zajmował 106. miejsce w grupie imion męskich.", "Sandor": "<b>Aleksander</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἀλέξανδρος, <i>aleksandros</i> – obrońca ludzi) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> składające się z dwóch członów: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;αλέξειν (bronić, wspomagać) i ἀνδρός (od ἀνήρ – mąż, mężczyzna). Całość bywa interpretowana jako „broniący mężów, troszczący się o mężów, opiekujący się mężami”.", "Skarbimir": "<b>Skarbimir</b>, <b>Skardmir</b>, <b>Skamir</b>, <b>Skarbimirz</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Skarbi-</i> („smucić, martwić, troszczyć się”) i <i>-mir</i> („pokój, spokój, dobro”). Może oznaczać „troszczący się o pokój”. Jako Skarbimir imię występuje od XII wieku.", "Salwator": "<b>Salwator</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> powstałe na bazie tytułu <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a> <i>Salvatora</i> oznaczającego 'zbawcę, zbawiciela'. Na gruncie <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskim</a> <i>Salvator</i> odnosi się zawsze do <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>.", "Swen": "<b>Swen</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a> <i>sveinn</i> – „młody mężczyzna”. Imię to pojawiło się również w Polsce. W 1994 roku w Polsce żyło 6 osób o tym imieniu; najstarsza z nich urodzona w <a href=\"https://pl.wikipedia.org/wiki/Lata_60._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">latach 60.</a>.", "Saddam": "<b>Saddam</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> <b>صدام</b>, <i>Ṣaddām</i>) – imię męskie pochodzenia arabskiego. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/Alternacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">rdzenia</a> Ṣ-D-M, oznaczającego \"przeciwstawiać się\".", "Sylwan": "<b>Sylwan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego \"las, zagajnik\". Imię to posiada również skróconą formę <a href=\"https://pl.wikipedia.org/wiki/Sylas\" target=\"_blank\" rel=\"noopener noreferrer\">Sylas</a>.", "Stanimir": "<b>Stanimir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członu <i>Stani-</i> (\"stać, stać się, stanąć\") oraz członu <i>-mir</i> (\"pokój, spokój, dobro\"). Mogło oznaczać \"niech się stanie pokój\" albo \"ten, który ustanawia pokój\".", "Sędzimir": "<b>Sędzimir</b>, <b>Sędomir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członu <i>Sędzi-</i> („sądzić”) oraz członu <i>-mir</i> („pokój, spokój, dobro”). Być może oznaczało „ten, komu sądzone jest życie w pokoju”. Od tego imienia, występującego w całej Słowiańszczyźnie (por. czes., rus. i serbsko-chor. <i>Sudomir</i>) pochodzi nazwa miasta <a href=\"https://pl.wikipedia.org/wiki/Sandomierz\" target=\"_blank\" rel=\"noopener noreferrer\">Sandomierz</a>.", "Sulisław": "<b>Sulisław</b>, <b>Solisław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>Suli-</i> („obiecywać” albo „lepszy, możniejszy”) i <i>-sław</i> („sława”). Może oznaczać „ten, który cieszy się lepszą sławą od innych”.", "Safar": "<b>Safar</b> (arab. <b>صفر</b>) jest drugim miesiącem <a href=\"https://pl.wikipedia.org/wiki/Kalendarz_muzu%C5%82ma%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">kalendarza muzułmańskiego</a> i tak jak wszystkie miesiące tego kalendarza jest ruchomy i przypada na różne pory roku. Podobno jego nazwa wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%BB%C3%B3%C5%82taczka_(medycyna)\" target=\"_blank\" rel=\"noopener noreferrer\">żółtaczki</a>, na którą to miano zapadać w porze roku przypadającej na miesiąc Safar przed reformą kalendarzową <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a>, choć jest to tylko jedna z kilku hipotez. W tym miesiącu obchodzono kiedyś święto powrotu pielgrzymów z Mekki.", "Satoshi": "<b>Satoshi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さとし, サトシ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Salwin": "<b>Salwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> oznaczające człowieka pełnego pokoju, spokojnego.", "Symforian": "<b>Symforian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznaczające „stosowny, odpowiedni”. Wśród patronów tego imienia – św. <a href=\"https://pl.wikipedia.org/wiki/Symforian_z_Autun\" target=\"_blank\" rel=\"noopener noreferrer\">Symforian</a> z dzisiejszego <a href=\"https://pl.wikipedia.org/wiki/Autun\" target=\"_blank\" rel=\"noopener noreferrer\">Autun</a> we <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a>.", "Seid": "<b>Seid</b> (staronordyckie <i>seiðr</i>) – forma <a href=\"https://pl.wikipedia.org/wiki/Szamanizm\" target=\"_blank\" rel=\"noopener noreferrer\">szamanizmu</a> (nie <a href=\"https://pl.wikipedia.org/wiki/Magia\" target=\"_blank\" rel=\"noopener noreferrer\">magii</a>), uprawiana przez przedchrześcijańskich <a href=\"https://pl.wikipedia.org/wiki/Wikingowie\" target=\"_blank\" rel=\"noopener noreferrer\">wikingów</a>. Termin ten odnosi się również do nowożytnych rekonstrukcji i kopii tych praktyk. Seid, czyli norrøn sjamanisme, powiązane było z podróżami astralnymi, transem szamańskim, leczeniem, zielarstwem, używaniem run, śpiewaniem gardłowym run, bębnieniem szamańskim, tańcem itp. Jak w większości przypadków tak i tutaj ważnym elementem był rytm.", "Świerad": "<b>Wszerad</b>, <b>Świerad</b>, <b>Świrad</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Wsze-</i> („wszystek, każdy, zawsze”) w różnych wersjach nagłosowych, oraz członu <i>-rad</i> („radosny, zadowolony”). Znaczenie imienia: „rad każdemu”.", "Sulejman": "<b>Salomon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> imienia שְׁלֹמֹה<i> (Shelomo)</i> należącego do słynnego z mądrości króla <a href=\"https://pl.wikipedia.org/wiki/Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">Izraela</a> – <a href=\"https://pl.wikipedia.org/wiki/Salomon_(kr%C3%B3l_Izraela)\" target=\"_blank\" rel=\"noopener noreferrer\">Salomona</a>. Istnieje kilku świętych katolickich o tym imieniu.", "Satoru": "<b>Satoru</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さとる, サトル) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Symplicjusz": "<b>Symplicjusz</b>, <b>Symplicy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzące od wyrazu <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>simplex</em>, oznaczającego „prosty, szczery, uczciwy”. W średniowieczu nie jest ono poświadczone w źródłach polskich, pojawiło się w <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII wieku</a>. Wersja <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Simplicius</em> została w polszczyźnie zaadaptowana na dwa sposoby: jako <i>Symplicjusz</i> (z odmianą rzeczownikową) oraz jako <i>Symplicy</i> (z odmianą przymiotnikową, jak <i><a href=\"https://pl.wikipedia.org/wiki/Ignacy\" target=\"_blank\" rel=\"noopener noreferrer\">Ignacy</a></i>).", "Sos": "<b>Sos</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">fr.</a> <i>sauce</i>) – gęsty płyn, tworzony na bazie różnych składników, nadających mu odmienne smaki (ostry, łagodny, kwaśny, słodki, umami), stosowany jako dodatek do: <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99so\" target=\"_blank\" rel=\"noopener noreferrer\">mięs</a>, <a href=\"https://pl.wikipedia.org/wiki/Ryby\" target=\"_blank\" rel=\"noopener noreferrer\">ryb</a>, <a href=\"https://pl.wikipedia.org/wiki/Makaron\" target=\"_blank\" rel=\"noopener noreferrer\">makaronów</a>, <a href=\"https://pl.wikipedia.org/wiki/W%C4%99dliny\" target=\"_blank\" rel=\"noopener noreferrer\">wędlin</a>, <a href=\"https://pl.wikipedia.org/wiki/Sa%C5%82atka\" target=\"_blank\" rel=\"noopener noreferrer\">sałatek</a>, <a href=\"https://pl.wikipedia.org/wiki/Deser\" target=\"_blank\" rel=\"noopener noreferrer\">deserów</a>, <a href=\"https://pl.wikipedia.org/wiki/Kanapka\" target=\"_blank\" rel=\"noopener noreferrer\">kanapek</a> itd. W konsystencji luźniejszy od kremu. Sosy dzielą się na: gorące, zimne i <a href=\"https://pl.wikipedia.org/wiki/Majonez\" target=\"_blank\" rel=\"noopener noreferrer\">majonezowe</a>. Istnieje też inny podział, wywodzący się z <a href=\"https://pl.wikipedia.org/wiki/Kuchnia_francuska\" target=\"_blank\" rel=\"noopener noreferrer\">kuchni francuskiej</a>, klasyfikujący sosy jako pochodne jednego z pięciu <a href=\"https://pl.wikipedia.org/wiki/Sosy_bazowe\" target=\"_blank\" rel=\"noopener noreferrer\">sosów bazowych</a>.", "Shingo": "<b>Shingo</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;しんご, シンゴ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Świętopełk": "<b>Świętopełk</b>, <b>Wszetopełk</b>, <b>Świętopałk</b>, <b>Świętopełek</b> – starodawne (obecnie rzadkie) <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> słowiańskie (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czes.</a> <i>Svatopluk</i>), oznacza <i>święty</i> (tj. silny, mocny) <i>pułk</i> (tj. oddział; dawne polskie <i>pełk/połk</i>, czes. <i>pluk</i>). Polskie „pełk”, „pułk”, powstało w wyniku wokalizacji pierwotnego <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">prasłowiańskiego</a> twardego zgłoskotwórczego „l” w języku polskim doby przedpiśmiennej w – zależnie od otoczenia fonetycznego – „oł”, „uł” albo „eł”.", "Sadam": "Do władzy doszedł po objęciu władzy w Iraku przez partię Baas, oficjalnie głoszącą <a href=\"https://pl.wikipedia.org/wiki/Socjalizm_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">socjalizm arabski</a> i <a href=\"https://pl.wikipedia.org/wiki/Panarabizm\" target=\"_blank\" rel=\"noopener noreferrer\">panarabizm</a>. Saddam odegrał znaczącą rolę w <a href=\"https://pl.wikipedia.org/wiki/Zamach_stanu_w_Iraku_(1968)\" target=\"_blank\" rel=\"noopener noreferrer\">zamachu stanu</a> przygotowanym przez tę partię w 1968. W latach 70. z jego inicjatywy <a href=\"https://pl.wikipedia.org/wiki/Nacjonalizacja\" target=\"_blank\" rel=\"noopener noreferrer\">znacjonalizowano</a> przemysł <a href=\"https://pl.wikipedia.org/wiki/Ropa_naftowa\" target=\"_blank\" rel=\"noopener noreferrer\">naftowy</a> w większości należący do zachodnich korporacji. Z pieniędzy pochodzących z ropy w szybkim tempie rozwinął gospodarkę Iraku. Husajn otoczył się w rządzie politykami wywodzącymi się z <a href=\"https://pl.wikipedia.org/wiki/Sunnizm\" target=\"_blank\" rel=\"noopener noreferrer\">sunnickiej</a> mniejszości kraju. Formalnie objął rządy w 1979, wtedy też miało miejsce apogeum jego władzy.", "Shinji": "<b>Shinji</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;しんじ, シンジ) – popularne męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Seiji": "<b>Seiji</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;せいじ, セイジ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Shijo": "Przed wstąpieniem na tron nosił imię książę Mitsuhito&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;秀仁親王&#32;<i>Mitsuhito-shinnō</i>). Był pierwszym synem cesarza <a href=\"https://pl.wikipedia.org/wiki/Go-Horikawa\" target=\"_blank\" rel=\"noopener noreferrer\">Go-Horikawa</a>.", "Spirydion": "<b>Spirydon</b>, <b>Spirydion</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, wywodzące się od słowa <i>spyridos</i> — \"koszyczek\". Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Spirydon_z_Tremituntu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Spirydon z Tremituntu</a>, biskup (IV wiek).", "Shiraz": "<b>Syrah</b> (znany także jako <b>shiraz</b> i <b>balsamia</b>) – czerwona <a href=\"https://pl.wikipedia.org/wiki/Kultywar\" target=\"_blank\" rel=\"noopener noreferrer\">odmiana</a> <a href=\"https://pl.wikipedia.org/wiki/Winoro%C5%9Bl_w%C5%82a%C5%9Bciwa\" target=\"_blank\" rel=\"noopener noreferrer\">winorośli</a>, wywodząca się z Doliny <a href=\"https://pl.wikipedia.org/wiki/Rodan\" target=\"_blank\" rel=\"noopener noreferrer\">Rodanu</a> we <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a>. W <a href=\"https://pl.wikipedia.org/wiki/Po%C5%82udniowa_Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Republice Południowej Afryki</a>, <a href=\"https://pl.wikipedia.org/wiki/Australia\" target=\"_blank\" rel=\"noopener noreferrer\">Australii</a>, <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">Stanach Zjednoczonych</a> powszechnie używa się nazwy shiraz. Syrah jest zaliczane do małej grupy „odmian szlachetnych” (<i>edle Rebsorten</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem</a>.), <i>Edelreben</i> (niem.), <i>cépages nobles</i> (fr.)).", "Shen": "<b>Shen</b> – pojęcie w tradycyjnej religii chińskiej oznaczające siłę ponadnaturalną. Może określać zarówno <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">bóstwa</a>, <a href=\"https://pl.wikipedia.org/wiki/Dusza_(religia)\" target=\"_blank\" rel=\"noopener noreferrer\">dusze</a> zmarłych przodków, duchy opiekuńcze konkretnych miejsc czy <a href=\"https://pl.wikipedia.org/wiki/Taoizm\" target=\"_blank\" rel=\"noopener noreferrer\">taoistycznych</a> świętych w rodzaju <a href=\"https://pl.wikipedia.org/wiki/O%C5%9Bmiu_Nie%C5%9Bmiertelnych\" target=\"_blank\" rel=\"noopener noreferrer\">Ośmiu Nieśmiertelnych</a>.", "Svend": "<b>Swen</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a> <i>sveinn</i> – „młody mężczyzna”. Imię to pojawiło się również w Polsce. W 1994 roku w Polsce żyło 6 osób o tym imieniu; najstarsza z nich urodzona w <a href=\"https://pl.wikipedia.org/wiki/Lata_60._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">latach 60.</a>.", "Sawin": "<b>Sawin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, od wyrazu <i>saba</i> – „zmiana, niewola, zajęcie”.", "Sieciech": "<b>Sieciech</b>, <b>Świeciech</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Wsze-</i> („wszystek, każdy, zawsze”) w wersjach nagłosowych <i>Sie-</i> lub <i>Świe-</i>, oraz członu <i>-ciech</i> („cieszyć”). Może ono oznaczać „tego, który wszystkich cieszy” albo „tego, który się ze wszystkiego cieszy”.", "S": "<b>S</b> (<i>es</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>s</b>) – dwudziesta czwarta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a> i dziewiętnasta <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>. Oznacza zwykle w danym języku spółgłoskę przedniojęzykową szczelinową bezdźwięczną, np. [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">s</a>].", "Sadok": "<b>Sadok</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, oznaczające \"słuszny\", \"sprawiedliwy\", \"prawidłowy\". Patronem tego imienia jest bł. Sadok, polski mnich z <a href=\"https://pl.wikipedia.org/wiki/Sandomierz\" target=\"_blank\" rel=\"noopener noreferrer\">Sandomierza</a>, zamordowany wraz z 48 towarzyszami w czasie najazdu <a href=\"https://pl.wikipedia.org/wiki/Z%C5%82ota_Orda\" target=\"_blank\" rel=\"noopener noreferrer\">Tatarów</a> w <a href=\"https://pl.wikipedia.org/wiki/1259\" target=\"_blank\" rel=\"noopener noreferrer\">1259</a> lub <a href=\"https://pl.wikipedia.org/wiki/1260\" target=\"_blank\" rel=\"noopener noreferrer\">1260</a> roku.", "Sewerian": "<b>Sewerian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> pochodzące od słowa <i>severus</i> – surowy, srogi. Jednym z patronów tego imienia jest św. Sewerian z Cezarei.", "Stojgniew": "<b>Stojgniew</b>, <b>Stoigniew</b>, <b>Stogniew</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Stoj(i)-</i> (\"stać, stoję\") oraz członu <i>-gniew</i> (\"gniew\"). Może oznaczać \"ten, którego gniew nie ustaje\".", "Svein": "<b>Swen</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a> <i>sveinn</i> – „młody mężczyzna”. Imię to pojawiło się również w Polsce. W 1994 roku w Polsce żyło 6 osób o tym imieniu; najstarsza z nich urodzona w <a href=\"https://pl.wikipedia.org/wiki/Lata_60._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">latach 60.</a>.", "Somon": "W XVIII w. po reformach administracyjnych Mongolii przeprowadzonej przez mandżurskie władze, w obrębie księstw <a href=\"https://pl.wikipedia.org/wiki/Choszun\" target=\"_blank\" rel=\"noopener noreferrer\">choszunów</a> wydzielono jednostki niższe, zwane somonami. Somony wyodrębniono głównie z powodu administracji wojskowej, gdyż była potrzeba podzielenia wojskowej jednostki choszunu (chorągwi, szwadronu) na mniejsze oddziały, czyli somony (kompanie). Każdy somon dostarczał terytorialną jednostkę <a href=\"https://pl.wikipedia.org/wiki/Pospolite_ruszenie\" target=\"_blank\" rel=\"noopener noreferrer\">pospolitego ruszenia</a>, którą też zwano somonem. Liczebność somonu jako jednostki wojskowej wynosiła około 150 jeźdźców, a somon jako jednostka administracyjna liczył około 150 jurt (zazwyczaj w jednej jurcie mieszkała jedna rodzina wielopokoleniowa). Natomiast cywilna administracja i odrębność somonów była słabo zaznaczona.", "Sulimir": "<b>Sulimir</b>, <b>Sulimiar</b>, <b>Sulmir</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>Suli-</i> (\"obiecywać\" albo \"lepszy, możniejszy\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Znaczenie imienia: \"przynoszący/obiecujący/lepszy pokój\".", "Sulibor": "<b>Sulibor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>Suli-</i> (\"obiecywać\" albo \"lepszy, możniejszy\") i <i>-bor</i> (\"walczyć, zmagać się\"). Może oznaczać \"obiecujący walkę\" albo \"ten, który lepiej walczy\".", "Soter": "<b>Soter</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Σωτήρ) – <a href=\"https://pl.wikipedia.org/wiki/Grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Oznacza „Zbawcę”, „Zbawiciela”. W łacinie odpowiadające imię to <a href=\"https://pl.wikipedia.org/wiki/Salwator_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Salwator</a>. W chrześcijaństwie odnoszono Σωτήρ do <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa</a>.", "Siarhiej": "<b>Sergiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pierwotne nomen gentilicium (nazwisko rodowe) <i>Sergius</i> (gens Sergia). Ród Sergia był starym rodem patrycjuszowskim. Pochodzenie nazwy rodu nie zostało jednoznacznie wyjaśnione. Nie można wykluczyć źródła etruskiego, jak przy wielu nazwach rodów rzymskich.", "Shigeru": "<b>Shigeru</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;しげる, シゲル) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Shi": "<b>Shi</b> (<a href=\"https://pl.wikipedia.org/wiki/Uproszczone_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chiń. upr.</a> 诗&#59;&#32;<a href=\"https://pl.wikipedia.org/wiki/Tradycyjne_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chiń. trad.</a> 詩&#59;&#32;<a href=\"https://pl.wikipedia.org/wiki/Hanyu_pinyin\" target=\"_blank\" rel=\"noopener noreferrer\">pinyin</a> <i>shī</i>) – forma poezji chińskiej zbliżona do <a href=\"https://pl.wikipedia.org/wiki/Oda_(literatura)\" target=\"_blank\" rel=\"noopener noreferrer\">ody</a>, przeważnie składa się z czterech lub ośmiu wierszy (czasami więcej), pojedyncza linia zawiera 5 lub 7 wyrazów/sylab.", "Shamo": "<b>Shamo</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;軍鶏) – rasa <a href=\"https://pl.wikipedia.org/wiki/Kura\" target=\"_blank\" rel=\"noopener noreferrer\">kur</a> wywodząca się z <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">Japonii</a>. Koguty tej rasy charakteryzują się wielkim temperamentem w stosunku do innych ras kur. Shamo daje się oswoić przez opiekuna. Waga koguta wynosi ok. 6 kg, a kury ok. 4,5 kg.", "Samba": "<b>Samba</b> – <a href=\"https://pl.wikipedia.org/wiki/Brazylia\" target=\"_blank\" rel=\"noopener noreferrer\">brazylijski</a> <a href=\"https://pl.wikipedia.org/wiki/Taniec_ludowy\" target=\"_blank\" rel=\"noopener noreferrer\">taniec ludowy</a> i zarazem gatunek muzyczno-taneczny pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">afrykańskiego</a>. Występuje w licznych odmianach form wykonawczych: może być wykonywana zespołowo przez grupy śpiewające i tańczące, przez pary w kontekście salonowym albo solowo.", "Siemomysł": "<b>Siemomysł</b>, <b>Siemimysł</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Siemo(i)-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*sěmьja</i> ma m.in. znaczenia „rodzina, ród; czeladź, służba, własność”) i <i>-mysł</i> („myśleć”). Imię to oznacza „myślący o swojej rodzinie”. Podobnie jak <a href=\"https://pl.wikipedia.org/wiki/Siemowit_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Siemowit</a>, imię to było charakterystyczne dla <a href=\"https://pl.wikipedia.org/wiki/Piastowie_mazowieccy\" target=\"_blank\" rel=\"noopener noreferrer\">Piastów mazowieckich</a>.", "Shinya": "<b>Shin’ya</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;しんや, シンヤ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Sabian": "<b>Sabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Kanada\" target=\"_blank\" rel=\"noopener noreferrer\">kanadyjski</a> producent <a href=\"https://pl.wikipedia.org/wiki/Talerze_perkusyjne\" target=\"_blank\" rel=\"noopener noreferrer\">talerzy perkusyjnych</a>, należy obok takich przedsiębiorstw jak <a href=\"https://pl.wikipedia.org/wiki/Avedis_Zildjian_Company\" target=\"_blank\" rel=\"noopener noreferrer\">Zildjian</a>, <a href=\"https://pl.wikipedia.org/wiki/Paiste\" target=\"_blank\" rel=\"noopener noreferrer\">Paiste</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Meinl\" target=\"_blank\" rel=\"noopener noreferrer\">Meinl</a> do liderów rynku. Przedsiębiorstwo powstało w 1981 roku w Meductic w <a href=\"https://pl.wikipedia.org/wiki/Nowy_Brunszwik\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Brunszwiku</a> z inicjatywy <a href=\"https://pl.wikipedia.org/wiki/Robert_Zildjian\" target=\"_blank\" rel=\"noopener noreferrer\">Roberta Zildjiana</a>, syna Avedisa Zildjiana III, prezesa przedsiębiorstwa Zildjian. <a href=\"https://pl.wikipedia.org/wiki/Firma\" target=\"_blank\" rel=\"noopener noreferrer\">Firma</a> Sabian pochodzi od dwóch pierwszych liter trójki dzieci właściciela firmy Sally, Billy oraz Andy.", "Shang": "Z czasów dynastii Shang pochodzą odkrywane od końca XIX w. <a href=\"https://pl.wikipedia.org/wiki/Napisy_na_br%C4%85zach\" target=\"_blank\" rel=\"noopener noreferrer\">inskrypcje</a> na <a href=\"https://pl.wikipedia.org/wiki/Chi%C5%84skie_br%C4%85zy_rytualne\" target=\"_blank\" rel=\"noopener noreferrer\">rytualnych naczyniach z brązu</a> oraz wróżebne <a href=\"https://pl.wikipedia.org/wiki/Napisy_na_ko%C5%9Bciach_wr%C3%B3%C5%BCebnych\" target=\"_blank\" rel=\"noopener noreferrer\">inskrypcje</a> na zwierzęcych kościach (lub skorupach żółwich）.", "Stasio": "<b>Stanisław „Stasio” Majda</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/8_maja\" target=\"_blank\" rel=\"noopener noreferrer\">8 maja</a> <a href=\"https://pl.wikipedia.org/wiki/1978\" target=\"_blank\" rel=\"noopener noreferrer\">1978</a>) – polski muzyk, wokalista, raper, autor tekstów i <a href=\"https://pl.wikipedia.org/wiki/Satyra\" target=\"_blank\" rel=\"noopener noreferrer\">satyryk</a>. Pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Zabrze\" target=\"_blank\" rel=\"noopener noreferrer\">Zabrza</a>. Zajmuje się też <a href=\"https://pl.wikipedia.org/wiki/Kino\" target=\"_blank\" rel=\"noopener noreferrer\">filmem</a>.", "Susumu": "<b>Susumu</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;すすむ, ススム) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Sasi": "<b>Sasi</b>, <b>Saksoni</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Saxones</em>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>&#160;<em>Sachsen</em>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>Saxons</em>) – plemię pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, osiadłe w <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a> w <a href=\"https://pl.wikipedia.org/wiki/Westfalia\" target=\"_blank\" rel=\"noopener noreferrer\">Westfalii</a> i <a href=\"https://pl.wikipedia.org/wiki/Dolna_Saksonia\" target=\"_blank\" rel=\"noopener noreferrer\">Dolnej Saksonii</a>.", "Spirydon": "<b>Spirydon</b>, <b>Spirydion</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, wywodzące się od słowa <i>spyridos</i> — \"koszyczek\". Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Spirydon_z_Tremituntu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Spirydon z Tremituntu</a>, biskup (IV wiek).", "Sandra": "<b>Sandra</b> – żeńskie imię powstałe jako usamodzielnione zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksandra\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra</a>; może stanowić również zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Kasandra_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kasandry</a>. W Polsce imię Sandra zaczęło być sporadycznie nadawane prawdopodobnie w latach 20 <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX</a> w., a większą popularność zdobyła w latach osiemdziesiątych XX w.; obecnie nadawalność tego imienia wykazuje tendencję spadkową. Wśród imion nadawanych nowo narodzonym dzieciom Sandra zajmuje aktualnie 61. miejsce w grupie imion żeńskich.", "Silvanus": "Miał być synem pasterza i kozy bądź kobiety z <a href=\"https://pl.wikipedia.org/wiki/Tusculum\" target=\"_blank\" rel=\"noopener noreferrer\">Tusculum</a> imieniem Valeria i jej własnego ojca. Był bogiem dokuczliwym, straszącym wędrowców przemierzających lasy, zaś Rzymianie straszyli nim dzieci.", "Sverre": "<b>Sverre</b> – tradycyjne <a href=\"https://pl.wikipedia.org/wiki/Norwegia\" target=\"_blank\" rel=\"noopener noreferrer\">norweskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię męskie</a> wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordycki\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyckiego</a> imienia <i>Sverrir</i>.", "Snowid": "<b>Snowid</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Sno-</i> (\"sen\") i <i>-wid</i> (\"widzieć\"). Może więc oznaczać \"tego, który widzi sny\".", "Sędzisław": "<b>Sędzisław</b>, <b>Sędosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członu <i>Sędzi-</i> („sądzić”) oraz członu <i>-sław</i> („sława”). Być może oznaczało „ten, komu sądzona jest sława”.", "Solidariusz": "<b>Solidariusz</b> – polskie imię męskie, stworzone w latach 80. XX wieku na cześć <a href=\"https://pl.wikipedia.org/wiki/Niezale%C5%BCny_Samorz%C4%85dny_Zwi%C4%85zek_Zawodowy_%E2%80%9ESolidarno%C5%9B%C4%87%E2%80%9D\" target=\"_blank\" rel=\"noopener noreferrer\">NSZZ „Solidarność”</a>. Jego nadawanie uznawane było za akt oporu przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/PZPR\" target=\"_blank\" rel=\"noopener noreferrer\">PZPR</a> i powodowało opór urzędników stanu cywilnego. Orzecznictwo <a href=\"https://pl.wikipedia.org/wiki/Naczelny_S%C4%85d_Administracyjny\" target=\"_blank\" rel=\"noopener noreferrer\">Naczelnego Sądu Administracyjnego</a> dopuściło jednak jego nadawanie.", "Sylas": "<b>Sylas</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, skrócona forma imienia <a href=\"https://pl.wikipedia.org/wiki/Sylwan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwan</a>, wywodzącego się od słowa <i>silva</i>, które oznacza \"las, zagajnik\".", "Siemisław": "<b>Siemisław</b>, <b>Siemosław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Siemo(i)-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*sěmьja</i> ma m.in. znaczenia „rodzina, ród; czeladź, służba, własność”) i <i>-sław</i> („sława”). Imię to wyraża życzenie sławy w przestrzeni rodzinnej.", "Sok": "<b>Sok</b> – produkt otrzymany z dojrzałych, świeżych lub przechowywanych <a href=\"https://pl.wikipedia.org/wiki/Owoc\" target=\"_blank\" rel=\"noopener noreferrer\">owoców</a> lub <a href=\"https://pl.wikipedia.org/wiki/Warzywa\" target=\"_blank\" rel=\"noopener noreferrer\">warzyw</a>, jednego lub większej liczby gatunków, posiadający <a href=\"https://pl.wikipedia.org/wiki/Barwa\" target=\"_blank\" rel=\"noopener noreferrer\">barwę</a>, <a href=\"https://pl.wikipedia.org/wiki/Smak_(fizjologia)\" target=\"_blank\" rel=\"noopener noreferrer\">smak</a> i <a href=\"https://pl.wikipedia.org/wiki/Zapach\" target=\"_blank\" rel=\"noopener noreferrer\">zapach</a> charakterystyczny dla soku z owoców lub warzyw, z których pochodzą, zdolny do <a href=\"https://pl.wikipedia.org/wiki/Fermentacja\" target=\"_blank\" rel=\"noopener noreferrer\">fermentacji</a>, lecz niesfermentowany. Soki mogą być produkowane z zagęszczonych soków lub przecierów przez odtworzenie udziału <a href=\"https://pl.wikipedia.org/wiki/Woda\" target=\"_blank\" rel=\"noopener noreferrer\">wody</a> usuniętej w procesie zagęszczania soku lub przecieru i odtworzenie aromatu oraz, gdy jest to wskazane, miazgi usuniętej z soku, lecz odzyskanej w procesie technologicznym.", "Światowid": "<b>Idol ze Zbrucza</b>, <b>idol zbruczański</b>, <b>idol z Liczkowiec</b>, <b><a href=\"https://pl.wikipedia.org/wiki/Ba%C5%82wan_(pos%C4%85g)\" target=\"_blank\" rel=\"noopener noreferrer\">bałwan</a> ze Zbrucza</b>, <a href=\"https://pl.wikipedia.org/wiki/Mowa_potoczna\" target=\"_blank\" rel=\"noopener noreferrer\">pot.</a> <b>Światowid</b> – kamienny <a href=\"https://pl.wikipedia.org/wiki/Idol_(wyobra%C5%BCenie)\" target=\"_blank\" rel=\"noopener noreferrer\">idol</a> pochodzący z XI wieku, wydobyty w 1848 roku z rzeki <a href=\"https://pl.wikipedia.org/wiki/Zbrucz\" target=\"_blank\" rel=\"noopener noreferrer\">Zbrucz</a> w pobliżu wsi <a href=\"https://pl.wikipedia.org/wiki/Liczkowce\" target=\"_blank\" rel=\"noopener noreferrer\">Liczkowce</a> koło <a href=\"https://pl.wikipedia.org/wiki/Husiatyn\" target=\"_blank\" rel=\"noopener noreferrer\">Husiatyna</a> na <a href=\"https://pl.wikipedia.org/wiki/Podole\" target=\"_blank\" rel=\"noopener noreferrer\">Podolu</a>.", "Scypion": "<b>Scypion</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pierwotnie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek\" target=\"_blank\" rel=\"noopener noreferrer\">przydomek</a>, wywodzi się od słowa <i>scipio</i>, <i>-onis</i> – \"laska, buława\" (otrzymywana przez <i><a href=\"https://pl.wikipedia.org/wiki/Ornamenta_triumphalia\" target=\"_blank\" rel=\"noopener noreferrer\">viri triumphales</a></i> i sojuszniczych władców). Imię częste w rodzie Korneliuszy.", "Samuel Alexander": "<b>Samuel Alexander</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/6_stycznia\" target=\"_blank\" rel=\"noopener noreferrer\">6 stycznia</a> <a href=\"https://pl.wikipedia.org/wiki/1859\" target=\"_blank\" rel=\"noopener noreferrer\">1859</a> w <a href=\"https://pl.wikipedia.org/wiki/Sydney\" target=\"_blank\" rel=\"noopener noreferrer\">Sydney</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/13_wrze%C5%9Bnia\" target=\"_blank\" rel=\"noopener noreferrer\">13 września</a> <a href=\"https://pl.wikipedia.org/wiki/1938\" target=\"_blank\" rel=\"noopener noreferrer\">1938</a> w <a href=\"https://pl.wikipedia.org/wiki/Manchester\" target=\"_blank\" rel=\"noopener noreferrer\">Manchesterze</a>) – brytyjski filozof żydowskiego pochodzenia urodzony w Australii. Filozofię studiował w <a href=\"https://pl.wikipedia.org/wiki/Oksford\" target=\"_blank\" rel=\"noopener noreferrer\">Oksfordzie</a>, a psychologię we Fryburgu Bryzgowijskim. W latach 1893–1924 wykładał filozofię w Manchesterze. Był zwolennikiem teorii ewolucji emergentnej&#65279;<a href=\"https://www.wikidata.org/wiki/Q1189456#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a> i przedstawicielem neorealizmu&#65279;<a href=\"https://www.wikidata.org/wiki/Q1468157#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>.", "Sebastianus": "Arystokrata pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Galia\" target=\"_blank\" rel=\"noopener noreferrer\">Galii</a>. Mianowany współcesarzem przez swego brata <a href=\"https://pl.wikipedia.org/wiki/Jowin\" target=\"_blank\" rel=\"noopener noreferrer\">Jowinusa</a> wkrótce po uzurpacji przez niego tronu cesarstwa zachodniorzymskiego w 411.", "Sabas": "<b>Sabbas, Sabas, Saba</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a>, od <i>saba</i> – „starzec, dziad, dziadek”. Jego patronem jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sawa\" target=\"_blank\" rel=\"noopener noreferrer\">święty Saba (Sawa)</a>, najważniejszy święty w <a href=\"https://pl.wikipedia.org/wiki/Serbski_Ko%C5%9Bci%C3%B3%C5%82_Prawos%C5%82awny\" target=\"_blank\" rel=\"noopener noreferrer\">Serbskiej Cerkwi</a>, a także inni święci, również katoliccy, w liczbie co najmniej piętnastu. <i><b>Sawa</b></i> zaś jest nowogrecką formą imienia, występującą na obszarze chrześcijaństwa prawosławnego, od której być może pochodzą m.in. takie nazwiska, jak Sawa, Sawka, Sawczyn, <a href=\"https://pl.wikipedia.org/wiki/Sawiccy\" target=\"_blank\" rel=\"noopener noreferrer\">Sawicki</a>.", "Sirin": "Siriny symbolizują smutek, cierpienie i rozpacz, podczas gdy podobne wyglądem <a href=\"https://pl.wikipedia.org/wiki/Alkonost_(folklor)\" target=\"_blank\" rel=\"noopener noreferrer\">alkonosty</a>, oznaczają szczęście i nadzieję. W przeciwieństwie do alkonostów siriny są nastawione wrogo do człowieka.", "Shigang": "Populacja dzielnicy Shigang w 2016 roku liczyła 15&#160;174 mieszkańców – 7291 kobiet i 7883 mężczyzn. Liczba gospodarstw domowych wynosiła 4899, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,1 osób.", "Stosław": "<b>Stojsław</b>, <b>Stoisław</b>, <b>Stosław</b>, <b>Tosław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone członu <i>Stoj(i)-</i> (\"stać, stoję\") oraz członu <i>-sław</i> (\"sława\"). Notowane w Polsce od <a href=\"https://pl.wikipedia.org/wiki/1145\" target=\"_blank\" rel=\"noopener noreferrer\">1145</a> roku, po raz pierwszy w formie Stojsław (<i>Stoyslaus</i>).", "Szaweł": "<b>Szaweł</b>, Saul – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (&#8207;שָׁאוּל&#8206; <i>šā’ūl</i> „uproszony, pożądany”).", "Satur": "<b>Satur</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"nasycony, usatysfakcjonowany\". Istnieje przynajmniej dwóch świętych o tym imieniu.", "Sany": "Nazwa marki „Sany” wywodzi się od transkrypcji na język angielski chińskiego słowa (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">chin</a>. 三一; <a href=\"https://pl.wikipedia.org/wiki/Hanyu_pinyin\" target=\"_blank\" rel=\"noopener noreferrer\">pinyin</a>: <i>Sānyī</i>). Słowo to w wolnym tłumaczeniu oznacza „trzy jeden” i jest powiązane z wizją firmy i trzema fundamentami: „Zbudować pierwszorzędne przedsiębiorstwo, wspierać pierwszorzędnych pracowników i wnosić pierwszorzędny wkład w społeczeństwo”. Wszystko ma swoje odzwierciedlenie w logo marki – to trzy połączone ze sobą jedynki.", "Sofroniusz": "<b>Sofroniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, złożone z elementów <i>sōs</i>- („zdrowy”) i -<i>phron</i> („duch, umysł”). Oznacza człowieka mądrego, rozumnego. Istnieje kilku świętych o tym imieniu.", "Salish": "Ponadto 3310 obywateli USA zadeklarowało w 2000 roku pochodzenie <i>wyłącznie Salish</i> (4739 – <i>wyłącznie lub m.in. Salish</i>), zaś 3464 innych określiło swe pochodzenie jako <i>wyłącznie Salish and Kootenai</i> (4203 – <i>wyłącznie lub m.in. Salish and Kootenai</i>).", "Sabil": "Z historycznego punktu widzenia takie budynki są strukturami o znaczeniu zarówno cywilnym, jak i religijnym w miastach muzułmańskich, przede wszystkim w miastach <a href=\"https://pl.wikipedia.org/wiki/Imperium_Osma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Imperium Osmańskiego</a> i <a href=\"https://pl.wikipedia.org/wiki/Su%C5%82tanat_mameluk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">sułtanacie mameluków</a>.", "Sebald": "<b>Sebald</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z członu <i>Se-</i> oznaczającego „zwycięstwo” i <i>-bald</i> - „odważny, śmiały”. Patronem tego imienia jest św. Sebald, pustelnik (<a href=\"https://pl.wikipedia.org/wiki/VIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VIII wiek</a>), kanonizowany w XV wieku przez <a href=\"https://pl.wikipedia.org/wiki/Papie%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">papieża</a> <a href=\"https://pl.wikipedia.org/wiki/Marcin_V\" target=\"_blank\" rel=\"noopener noreferrer\">Marcina V</a>.", "Sława": "<b>Sława</b> (m., f.) – forma skrócona <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a> zawierających element <i>Sław-</i> lub <i>-sława</i>, takich jak <a href=\"https://pl.wikipedia.org/wiki/Miros%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Mirosława</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82awomira\" target=\"_blank\" rel=\"noopener noreferrer\">Sławomira</a>.", "Spytek": "<b>Spycimir</b>, <b>Spyćmier</b>, <b>Spyćmir</b>, <b>Spyćmierz</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Spyci-</i> („nadaremnie”), oraz członu <i>-mir</i> („pokój, spokój, dobro”), zdrobniale – <b>Spytko</b>. Pisownia z końcowym <i>-rz</i> prawdopodobnie jest zapisem imienia zdrobniałego, uformowanego przy użyciu przyrostka <i>-jь</i>, pod wpływem którego wygłosowe <i>-r</i> przeszło w <i>-rz</i>.", "Sara": "<b>Sara</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׂרָה, spokrewnione z <a href=\"https://pl.wikipedia.org/wiki/Dialekt_babilo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">babil.</a> <i>Szarratu</i> – „księżniczka”, postać wysokiej rangi) – postać <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijna</a>, bohaterka <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Rodzaju</a>, córka <a href=\"https://pl.wikipedia.org/wiki/Terach\" target=\"_blank\" rel=\"noopener noreferrer\">Teracha</a>, żona <a href=\"https://pl.wikipedia.org/wiki/Abraham\" target=\"_blank\" rel=\"noopener noreferrer\">Abrahama</a>, matka <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaaka</a>. Pierwotnie jej imię brzmiało Sarai (hebr. שָׂרָי), według Księgi Rodzaju (Rdz 17,15) Bóg zmienił je na Sara w ramach przymierza zawartego po tym, jak jej niewolnica <a href=\"https://pl.wikipedia.org/wiki/Hagar_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Hagar</a> doczekała się z jej mężem syna <a href=\"https://pl.wikipedia.org/wiki/Izmael\" target=\"_blank\" rel=\"noopener noreferrer\">Izmaela</a>.", "Siemirad": "<b>Siemirad</b> — staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Siemo(i)-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*sěmьja</i> ma m.in. znaczenia \"rodzina, ród; czeladź, służba, własność\") i <i>-rad</i> (\"cieszyć się\"), mówiące o radości skierowanej do obdarzonego imieniem.", "Siem": "<b>Simargł</b> (także <b>Siemargł</b>, <b>Semargł</b>) lub <b>Siem</b> i <b>Rgieł</b> – wschodniosłowiański bóg lub bogowie, wspomnieni w dwóch źródłach. Pochodzenie i etymologia tej/tych postaci jest przedmiotem ożywionej dyskusji. Dominującym poglądem jest interpretowanie Siemargła jako jednego bóstwa, który został zapożyczony od irańskiego <a href=\"https://pl.wikipedia.org/wiki/Simurg\" target=\"_blank\" rel=\"noopener noreferrer\">Simurga</a>. Pogląd ten jednak jest krytykowany, a część badaczy proponuje by uznać istnienie dwóch bóstw: Siema i Rgła.", "Spytko": "<b>Spycimir</b>, <b>Spyćmier</b>, <b>Spyćmir</b>, <b>Spyćmierz</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Spyci-</i> („nadaremnie”), oraz członu <i>-mir</i> („pokój, spokój, dobro”), zdrobniale – <b>Spytko</b>. Pisownia z końcowym <i>-rz</i> prawdopodobnie jest zapisem imienia zdrobniałego, uformowanego przy użyciu przyrostka <i>-jь</i>, pod wpływem którego wygłosowe <i>-r</i> przeszło w <i>-rz</i>.", "Salwiusz": "<b>Salwiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, genetycznie wtórne <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">cognomen</a> utworzone od pierwotnego <i>Salvus, Salvius</i>, co oznacza 'pochodzący od Salvusa, z rodu Salvusa'.", "Stylian": "<b>Stylian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od gr. <i>στυλος (stylos)</i> — \"filar\". Patronem tego imienia jest św. Stylian, pustelnik z <a href=\"https://pl.wikipedia.org/wiki/Edirne\" target=\"_blank\" rel=\"noopener noreferrer\">Adrianopolu</a> (VII wiek), patron dzieci.", "Stanisław Wojciech": "<b>Stanisław Jan Wojciech</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/1946\" target=\"_blank\" rel=\"noopener noreferrer\">1946</a>) – polski <a href=\"https://pl.wikipedia.org/wiki/Informatyka\" target=\"_blank\" rel=\"noopener noreferrer\">informatyk</a>, profesor <a href=\"https://pl.wikipedia.org/wiki/Nauki_techniczne\" target=\"_blank\" rel=\"noopener noreferrer\">nauk technicznych</a>.", "Shoufeng": "Populacja gminy Shoufeng w 2016 roku liczyła 18&#160;146 mieszkańców – 8471 kobiet i 9675 mężczyzn. Liczba gospodarstw domowych wynosiła 7114, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 2,55 osób.", "Simona": "<b>Szymona</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i><b>שמעון</b></i> <i>Szim'eon</i> – \"<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Bóg</a> wysłuchał\") – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Szymon\" target=\"_blank\" rel=\"noopener noreferrer\">Szymon</a>, pochodzenia biblijnego. Innym, bardziej rozpowszechnionym w Polsce żeńskim odpowiednikiem imienia Szymon jest <a href=\"https://pl.wikipedia.org/wiki/Ksymena\" target=\"_blank\" rel=\"noopener noreferrer\">Ksymena</a>, zapośredniczona przez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">język hiszpański</a>.", "Sonet": "Forma ta ukształtowana została we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a> w XIII – XIV wieku na podstawie wzorów z poezji ludowej. Twórcą sonetu jest poeta szkoły sycylijskiej <a href=\"https://pl.wikipedia.org/wiki/Iacopo_da_Lentini\" target=\"_blank\" rel=\"noopener noreferrer\">Iacopo (Giacomo) da Lentini</a>. Po nim sonet rozwijali <a href=\"https://pl.wikipedia.org/wiki/Guido_Cavalcanti\" target=\"_blank\" rel=\"noopener noreferrer\">Guido Cavalcanti</a>, <a href=\"https://pl.wikipedia.org/wiki/Guido_Guinizelli\" target=\"_blank\" rel=\"noopener noreferrer\">Guido Guinizelli</a>, <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dante Alighieri</a> i <a href=\"https://pl.wikipedia.org/wiki/Francesco_Petrarca\" target=\"_blank\" rel=\"noopener noreferrer\">Francesco Petrarca</a>. W okresie renesansu sonety pisał <a href=\"https://pl.wikipedia.org/wiki/Micha%C5%82_Anio%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Michał Anioł</a>; wymieniał sonety z <a href=\"https://pl.wikipedia.org/wiki/Vittoria_Colonna\" target=\"_blank\" rel=\"noopener noreferrer\">Vittorią Colonną</a>.", "Szalom": "Występuje także w złożeniu <i>szalom alejchem</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שָׁלוֹם עֲלֵיכֶם&#8206; <i>szalom ale(j)chem</i>, <a href=\"https://pl.wikipedia.org/wiki/Jidysz\" target=\"_blank\" rel=\"noopener noreferrer\">jid.</a>&#160;&#8207;שלום־עליכם&#8206; <i>szolem-alejchem</i>), co oznacza „pokój wam”, a na co odpowiada się najczęściej <i>alejchem szalom</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;עֲלֵיכֶם שָׁלוֹם&#8206; <i>ale(j)chem szalom</i>, <a href=\"https://pl.wikipedia.org/wiki/Jidysz\" target=\"_blank\" rel=\"noopener noreferrer\">jid.</a>&#160;&#8207;עליכם־שלום&#8206; <i>alejchem-szolem</i>) – „i wam pokój”.", "Saki": "<b>Saki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さき, サキ, 咲) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Sygurd": "<b>Zygfryd</b>, <b>Sygurd</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>sigu</i> i <i>fridu</i> oznaczających <i>zwycięstwo</i> i <i>opieka</i>, jako ten, który zapewnia bezpieczeństwo swym podopiecznym. Imię to było znane w Polsce od średniowiecza, m.in. w formach: Zebrzyd, Zybrzyd, Zewrzyd, Zywrzyd. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Zygfryda\" target=\"_blank\" rel=\"noopener noreferrer\">Zygfryda</a>.", "Serwiusz": "<b>Serwiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do nielicznej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Marek\" target=\"_blank\" rel=\"noopener noreferrer\">Marek</a>, <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>), oznaczające \"syn niewolnika\" (por. <i>servus</i> — \"niewolnik\"). Zaliczało się ono do tych najstarszych imion rzymskich, które były używane tylko przez niektóre rody.", "Sariel": "<b>Sariel</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajski</a>: שָׂרִיאֵל, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecki</a>: <i>Ατριήλ</i> \"rozkaz Boży\") jest jednym z archaniołów głównie z tradycji <a href=\"https://pl.wikipedia.org/wiki/Judaizm\" target=\"_blank\" rel=\"noopener noreferrer\">judaistycznej</a>. Inne możliwe wersje jego imienia to Suriel, Suriyel (w niektórych tłumaczeniach z basenu <a href=\"https://pl.wikipedia.org/wiki/Morze_Martwe\" target=\"_blank\" rel=\"noopener noreferrer\">Morza Martwego</a>), Esdreel, Sahariel, Juriel, Seriel, Sauriel, Surya, Saraqael, Sarakiel, Jariel, Suruel, Surufel i Sourial.", "Siemir": "<b>Wszemir</b>, <b>Wszemiar</b>, <b>Świemir</b>, <b>Siemir</b>, <b>Siemar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Wsze-</i> („wszystek, każdy, zawsze”) w różnych wersjach nagłosowych, oraz członu <i>-mir</i> („pokój, spokój, dobro”).", "Sędziwoj": "<b>Sędziwoj</b>, <b>Sędowoj</b>, <b>Sędźwoj</b>, <b>Sudywoj</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Znaczenie imienia: „ten, który sądzi wojowników”.", "Sabih": "Po raz pierwszy danie pojawiło się w Izraelu w latach 50. XX wieku, w miasteczku <a href=\"https://pl.wikipedia.org/wiki/Ramat_Gan\" target=\"_blank\" rel=\"noopener noreferrer\">Ramat Gan</a>. Została tam sprowadzona przez osiedlających się tam Żydów irakijskich. Nazwa potrawy pochodzi, według niektórych źródeł, od arabskiego słowa <i>sabah</i> oznaczającego \"poranek\", według innych – od nazwiska irakijskiego imigranta, który spopularyzował tę potrawę w Izraelu.", "Soledad": "<b>Soledad</b> – żeńskie imię hiszpańskie oznaczające <i>Samotność</i>.", "Swetoniusz": "Pochodził ze stanu <a href=\"https://pl.wikipedia.org/wiki/Ekwici\" target=\"_blank\" rel=\"noopener noreferrer\">ekwickiego</a>. Jego ojciec, Swetoniusz Laetus, był trybunem wojskowym przy XIII Legionie, gdzie walczył pod Bedriakum w oddziałach Otona, o czym Swetoniusz informuje w żywocie Otona.", "Shanlin": "Populacja dzielnicy Shanlin w 2016 roku liczyła 12&#160;201 mieszkańców – 5522 kobiety i 6679 mężczyzn. Liczba gospodarstw domowych wynosiła 4806, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 2,54 osób.", "Sartono": "Pochodził z rodziny arystokratycznej. Studiował na <a href=\"https://pl.wikipedia.org/wiki/Uniwersytet_w_Lejdzie\" target=\"_blank\" rel=\"noopener noreferrer\">uniwersytecie w Leiden</a>. Był jednym z założycieli Ligi Narodowej Indonezji (1927), przekształconej później (1928) w <a href=\"https://pl.wikipedia.org/wiki/Indonezyjska_Partia_Narodowa\" target=\"_blank\" rel=\"noopener noreferrer\">Indonezyjską Partię Narodową</a>. Przewodniczył parlamentowi Republiki Indonezji (1949–1959).", "Szarif": "<b>Szarif</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;شريف مكة&#8206;) – tytuł władców <a href=\"https://pl.wikipedia.org/wiki/Mekka\" target=\"_blank\" rel=\"noopener noreferrer\">Mekki</a>. Dynastia potomków <a href=\"https://pl.wikipedia.org/wiki/Hasan_ibn_Ali\" target=\"_blank\" rel=\"noopener noreferrer\">Hasana</a>, syna <a href=\"https://pl.wikipedia.org/wiki/Kalif\" target=\"_blank\" rel=\"noopener noreferrer\">kalifa</a> <a href=\"https://pl.wikipedia.org/wiki/Ali_ibn_Abi_Talib\" target=\"_blank\" rel=\"noopener noreferrer\">Alego</a> i <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">Fatimy</a>. Objęli władzę w <a href=\"https://pl.wikipedia.org/wiki/Mekka\" target=\"_blank\" rel=\"noopener noreferrer\">Mekce</a> około 960 r. Szarifowie byli zaangażowani w walki wewnętrzne między lokalnymi władcami <a href=\"https://pl.wikipedia.org/wiki/Arabia\" target=\"_blank\" rel=\"noopener noreferrer\">Arabii</a>, co uniemożliwiło im stworzenie silnego organizmu państwowego. Choć formalnie zachowywali niezależność, byli zawsze uzależnieni od władzy <a href=\"https://pl.wikipedia.org/wiki/Kalif\" target=\"_blank\" rel=\"noopener noreferrer\">kalifów</a>, a następnie <a href=\"https://pl.wikipedia.org/wiki/Su%C5%82tanat_mameluk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Mameluków</a> i <a href=\"https://pl.wikipedia.org/wiki/Imperium_Osma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Osmanów</a>. Ostatni szarif został obalony przez <a href=\"https://pl.wikipedia.org/wiki/Saudowie\" target=\"_blank\" rel=\"noopener noreferrer\">Saudów</a> w 1925 r.", "Spartakus": "<b>Spartakus</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Σπάρτακος <i>Spártakos</i>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Spartacus</i>; zm. <a href=\"https://pl.wikipedia.org/wiki/71_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">71 p.n.e.</a>) – <a href=\"https://pl.wikipedia.org/wiki/Niewolnictwo\" target=\"_blank\" rel=\"noopener noreferrer\">niewolnik</a>, <a href=\"https://pl.wikipedia.org/wiki/Gladiator\" target=\"_blank\" rel=\"noopener noreferrer\">gladiator</a> rzymski, z pochodzenia prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/Trakowie\" target=\"_blank\" rel=\"noopener noreferrer\">Trak</a>. Przywódca największego i najgroźniejszego w historii Rzymu powstania niewolników, od jego imienia nazywanego <a href=\"https://pl.wikipedia.org/wiki/Powstanie_Spartakusa\" target=\"_blank\" rel=\"noopener noreferrer\">powstaniem Spartakusa</a>.", "Sabrina": "<b>Sabrina</b> – <a href=\"https://pl.wikipedia.org/wiki/Anglia\" target=\"_blank\" rel=\"noopener noreferrer\">angielskie</a> imię żeńskie. Pochodzi od nazwy <a href=\"https://pl.wikipedia.org/wiki/Walia\" target=\"_blank\" rel=\"noopener noreferrer\">walijskiej</a> rzeki – <a href=\"https://pl.wikipedia.org/wiki/Severn\" target=\"_blank\" rel=\"noopener noreferrer\">Severn</a> (oryg. Habren). Błędną teorią jest, że Sabrina to forma pochodna imienia <a href=\"https://pl.wikipedia.org/wiki/Sabina\" target=\"_blank\" rel=\"noopener noreferrer\">Sabina</a>. Patronką tego imienia w Kościele katolickim jest św. Sabrina, męczennica z <a href=\"https://pl.wikipedia.org/wiki/Galia\" target=\"_blank\" rel=\"noopener noreferrer\">Galii</a>.", "Strogobor": "<b>Strogobor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Strogo-</i> (\"srogo\") oraz członu <i>-bor</i> (\"walczyć, zmagać się\"). Mogło oznaczać \"tego, który zaciekle walczy\".", "Sławosław": "<b>Sławosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Sławo-</i> („sława”) i <i>-sław</i> („sława”). <a href=\"https://pl.wikipedia.org/wiki/Andrzej_Ba%C5%84kowski\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej Bańkowski</a> twierdzi, że imię to najprawdopodobniej pierwotnie brzmiało <b>Słabosław</b>. Może oznaczać „ten, kto sławi sławę”.", "Sakae": "<b>Sakae</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さかえ, サカエ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">japońskie imię</a> używane zarówno przez mężczyzn, jak i kobiety.", "Sylwery": "<b>Sylweriusz</b>, <b>Sylwery</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, którego patronem jest <a href=\"https://pl.wikipedia.org/wiki/Sylweriusz_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">papież Sylweriusz</a>.", "Sulpicjusz": "<b>Sulpicjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pierwotnie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a>. Jego etymologia jest niejasna, można przypuszczać, że <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_etruski\" target=\"_blank\" rel=\"noopener noreferrer\">etruska</a>.", "Suen": "<b>Nanna, Nannar</b> – <a href=\"https://pl.wikipedia.org/wiki/Sumerowie\" target=\"_blank\" rel=\"noopener noreferrer\">sumeryjski</a> <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3stwa_lunarne\" target=\"_blank\" rel=\"noopener noreferrer\">bóg Księżyca</a>. Nazywany też był <i>Suen, Zuen</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akad.</a> <b>Sin</b>). Inne imiona: <i>Aszimbabar</i>, <i>Namrasit</i>, <i>Inbu</i>. Jego imię zapisywano również liczbą trzydzieści (tyle jest dni w <a href=\"https://pl.wikipedia.org/wiki/Miesi%C4%85c_synodyczny\" target=\"_blank\" rel=\"noopener noreferrer\">miesiącu synodycznym</a>).", "Sylwia": "<b>Sylwia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> Silvia) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Sylwiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwiusz</a> (nie: <a href=\"https://pl.wikipedia.org/wiki/Sylwester\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwester</a>), imię pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „leśna” lub „żyjąca w lesie”. Były dwie święte o tym imieniu.", "Stanisława": "<b>Stanisława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członu <i>Stani-</i> („stać, stać się, stanąć”) oraz członu <i>-sława</i> („sława”). Wywodzi się od słów oznaczających „stań się sławną”. Męskie odpowiedniki: <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stanisław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stasław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Tasław</a>. W źródłach polskich poświadczone od XIII wieku.", "Stefania": "<b>Stefania</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>.", "Sabina": "<b>Sabina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> męskiego <a href=\"https://pl.wikipedia.org/wiki/Sabin\" target=\"_blank\" rel=\"noopener noreferrer\">Sabin</a>.", "Sonia": "<b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sławomira": "<b>Sławomira</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Sławo-</i> („sława”) i <i>-mira</i> („pokój, spokój, dobro”). Mogło oznaczać „sławiąca pokój”. Notowane w źródłach od <a href=\"https://pl.wikipedia.org/wiki/1386\" target=\"_blank\" rel=\"noopener noreferrer\">1386</a> roku, występujące także w wariantach <i><b>Sławomirz</b></i> (fem.) i <i><b>Sławomirza</b></i>. Przykładowe dawne możliwe zdrobnienia: Sławna, Sławka, Sławnica, Sławocha.", "Samanta": "<b>Samanta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o semickim – aramejskim – pochodzenia. Znaczyć mogło <i>słuchająca</i>, ale inne źródła sugerują związek z imieniem męskim Samuel. Imię ma stosunkowo krótką historię. Pojedyncze wypadki wystąpienia tego imienia odkryto w kronikach rodzin z Nowej Anglii z <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII wieku</a>. Nie używano go praktycznie do lat siedemdziesiątych <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX wieku</a>, kiedy w telewizji pojawił się serial „Bewitched”, w Polsce nadawany pod tytułem „<a href=\"https://pl.wikipedia.org/wiki/O%C5%BCeni%C5%82em_si%C4%99_z_czarownic%C4%85_(serial_telewizyjny)\" target=\"_blank\" rel=\"noopener noreferrer\">Ożeniłem się z czarownicą</a>”. Jego tytułowa bohaterka, sympatyczna czarownica, nosiła właśnie imię Samantha. Od tego czasu imię Samanta stało się bardziej powszechne.", "Stella": "<b>Stella</b>, <b>Stela</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego gwiazdę. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Estella_(m%C4%99czennica)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Stella</a>, żyjąca w <a href=\"https://pl.wikipedia.org/wiki/Galia\" target=\"_blank\" rel=\"noopener noreferrer\">Galii</a> w <a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wieku</a>. Stella występuje w <i><a href=\"https://pl.wikipedia.org/wiki/Fantazy\" target=\"_blank\" rel=\"noopener noreferrer\">Fantazym</a></i> <a href=\"https://pl.wikipedia.org/wiki/Juliusz_S%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusza Słowackiego</a>, a jako imię chrzestne była notowana w Polsce co najmniej od 1820 roku.", "Salomea": "<b>Salomea</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się, podobnie jak imię męskie <a href=\"https://pl.wikipedia.org/wiki/Salomon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Salomon</a>, od hebrajskiego słowa <i>šalom</i> oznaczającego „pokój”, „pomyślność”. Judejska księżniczka <a href=\"https://pl.wikipedia.org/wiki/Salome_III\" target=\"_blank\" rel=\"noopener noreferrer\">Salome</a> tańcem skłoniła <a href=\"https://pl.wikipedia.org/wiki/Herod_Antypas\" target=\"_blank\" rel=\"noopener noreferrer\">Heroda</a> do wydania wyroku na <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jana Chrzciciela</a>. W Polsce imię to zanotowano w XII wieku. Nosiły je m.in. księżniczki piastowskie.", "Sarah": "<b>Sara</b>, z języka angielskiego <b>Sarah</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, oznacza: „księżniczka”.", "Seweryna": "<b>Seweryna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Forma żeńska imienia <a href=\"https://pl.wikipedia.org/wiki/Seweryn\" target=\"_blank\" rel=\"noopener noreferrer\">Seweryn</a>. Patronką tego imienia jest św. Septymia Seweryna, wspominana razem ze swoim mężem, św. Flawiuszem Juliuszem Katerwiuszem i synem, św. Bassusem.", "Sybilla": "<b>Sybilla</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>; w mitologii greckiej <a href=\"https://pl.wikipedia.org/wiki/Sybilla_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">wieszczka</a> przepowiadająca przyszłość.", "Swietłana": "<b>Świetlana</b>, <b>Swietłana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Stanowi ona literackie tłumaczenie greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Fotyna\" target=\"_blank\" rel=\"noopener noreferrer\">Fotyna</a> na rosyjski. Oznacza „jasną, świetlistą”. Imię bardzo popularne w XX wieku w <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a>, na <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82oru%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Białorusi</a>, <a href=\"https://pl.wikipedia.org/wiki/Ukraina\" target=\"_blank\" rel=\"noopener noreferrer\">Ukrainie</a> i w <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgarii</a>, ale spotykane także w innych krajach słowiańskich, np. na <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owacja\" target=\"_blank\" rel=\"noopener noreferrer\">Słowacji</a>; wcześniej nieistniejące lub bardzo rzadkie.", "Sylwestra": "<b>Sylwestra</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Sylwester\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwester</a>, utworzonego od przymiotnika <i>silvestris</i>, co oznacza „żyjący w lesie, dziki”. Istnieje dziesięciu świętych Sylwestrów, patronów tego imienia.", "Scholastyka": "<b>Scholastyka</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Zaczęto go używać w <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a>. Wywodzi się od łacińskiego słowa <i>scholasticus</i> oznaczającego <i>uczony, student, nauczyciel</i>.", "Szarlota": "<b>Karolina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>. Innym żeńskim odpowiednikiem imienia Karol jest <a href=\"https://pl.wikipedia.org/wiki/Karola\" target=\"_blank\" rel=\"noopener noreferrer\">Karola</a>. Imię Karolina jest pochodzenia starogermańskiego, od słowa charal, carl.", "Serafina": "<b>Serafina</b> – żeński odpowiednik hebrajskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Serafin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serafin</a>.", "Sylwana": "<b>Sylwana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego \"las, zagajnik\". Wbrew czasem powtarzanym informacjom żeńskie imię Sylwana nie ma patronki. Istnieje święty, ale Sylwan (zobacz: <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sylwan\" target=\"_blank\" rel=\"noopener noreferrer\">Święty Sylwan</a>).", "Saturnina": "<b>Saturnina</b> – żeński odpowiednik łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Saturnin\" target=\"_blank\" rel=\"noopener noreferrer\">Saturnin</a>. Imię to nosiło kilka świętych katolickich: Saturnina, męczennica rzymska, Saturnina z Neuenheerse i Saturnina z <a href=\"https://pl.wikipedia.org/wiki/Arras_(Francja)\" target=\"_blank\" rel=\"noopener noreferrer\">Arras</a>.", "Sylwina": "<b>Sylwina</b> – <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Sylwin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwin</a>, które zostało utworzone od <a href=\"https://pl.wikipedia.org/wiki/Sylwiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwiusza</a> przy pomocy <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-inus</i>, który wskazywał na pochodzenie od kogoś lub zdrabniał. Imię to nadawane jest w Polsce co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1827\" target=\"_blank\" rel=\"noopener noreferrer\">1827</a> roku.", "Świętosława": "<b>Świętosława</b>, <b>Święcsława</b>, <b>Święsława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie. Złożone jest z członu <i>Święto-</i> („święty”, „silny, mocny”) i <i>-sława</i> („sława”). Może oznaczać: „ta, której sława jest mocna”.", "Serena": "<b>Serena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od słowa oznaczającego „czysta, spokojna, pogodna”. Patronem tego imienia jest św. Seren, męczennik (<a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wiek</a>).", "Sydonia": "<b>Sydonia</b>, <b>Sidonia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>, oznaczające „kobieta z miasta <i><a href=\"https://pl.wikipedia.org/wiki/Sydon\" target=\"_blank\" rel=\"noopener noreferrer\">Sydon</a></i>”. Imię to pojawiło się w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX</a> w. Uważano niekiedy, że czeskie imię <i>Zdenka</i> jest odpowiednikiem Sydonii, niemniej rozpowszechnienie tego pierwszego imienia już w <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII</a>–<a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a> i względna rzadkość Sydonii powodują, że należy zakładać, iż imion tych nie łączy ze sobą związek.", "Samuela": "<b>Samuela</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Samuel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Samuel</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskich</a> słów oznaczających „imię Boże” lub niech „Bóg wysłucha”.", "Szczęsna": "<b>Szczęsna</b> – staropolskie&#8201; <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Wywodzi się od słowa \"szczęśliwa\". Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Szcz%C4%99sny\" target=\"_blank\" rel=\"noopener noreferrer\">Szczęsny</a>; jest uważana za odpowiednik znaczeniowy <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Feliksa\" target=\"_blank\" rel=\"noopener noreferrer\">Feliksa</a>, <a href=\"https://pl.wikipedia.org/wiki/Felicja\" target=\"_blank\" rel=\"noopener noreferrer\">Felicja</a>. Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Zygmunt_Szcz%C4%99sny_Feli%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Zygmunt Szczęsny Feliński</a>.", "Świetłana": "<b>Świetlana</b>, <b>Swietłana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Stanowi ona literackie tłumaczenie greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Fotyna\" target=\"_blank\" rel=\"noopener noreferrer\">Fotyna</a> na rosyjski. Oznacza „jasną, świetlistą”. Imię bardzo popularne w XX wieku w <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a>, na <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82oru%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Białorusi</a>, <a href=\"https://pl.wikipedia.org/wiki/Ukraina\" target=\"_blank\" rel=\"noopener noreferrer\">Ukrainie</a> i w <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgarii</a>, ale spotykane także w innych krajach słowiańskich, np. na <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owacja\" target=\"_blank\" rel=\"noopener noreferrer\">Słowacji</a>; wcześniej nieistniejące lub bardzo rzadkie.", "Samara": "<b>Samara</b> – imię żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>.", "Safira": "<b>Safira</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">egipskiego</a>. Może być inną formą imion Zefira czy <a href=\"https://pl.wikipedia.org/wiki/Zefiryna\" target=\"_blank\" rel=\"noopener noreferrer\">Zefiryna</a> - od przekształcenia nazwy <i>Saphira</i> - <i>Sephira</i> - <i>Sephirine</i>.", "Świetlana": "<b>Świetlana</b>, <b>Swietłana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Stanowi ona literackie tłumaczenie greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Fotyna\" target=\"_blank\" rel=\"noopener noreferrer\">Fotyna</a> na rosyjski. Oznacza „jasną, świetlistą”. Imię bardzo popularne w XX wieku w <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a>, na <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82oru%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Białorusi</a>, <a href=\"https://pl.wikipedia.org/wiki/Ukraina\" target=\"_blank\" rel=\"noopener noreferrer\">Ukrainie</a> i w <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgarii</a>, ale spotykane także w innych krajach słowiańskich, np. na <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owacja\" target=\"_blank\" rel=\"noopener noreferrer\">Słowacji</a>; wcześniej nieistniejące lub bardzo rzadkie.", "Siobhan": "<b>Joanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Jan\" target=\"_blank\" rel=\"noopener noreferrer\">Jan</a> pochodzącego z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języka hebrajskiego</a>: Jo-hanan – „<a href=\"https://pl.wikipedia.org/wiki/Tetragram\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> jest łaskawy”.", "Sulisława": "<b>Sulisława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z dwóch członów: <i>Suli-</i> („obiecywać” albo „lepszy, możniejszy”) i <i>-sława</i>. Może oznaczać „ta, która cieszy się lepszą sławą od innych”. W źródłach polskich poświadczone jako Sulisława (1228) i zdrobnienie <b>Sulichna</b> (1136).", "Sidonia": "<b>Sydonia</b>, <b>Sidonia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>, oznaczające „kobieta z miasta <i><a href=\"https://pl.wikipedia.org/wiki/Sydon\" target=\"_blank\" rel=\"noopener noreferrer\">Sydon</a></i>”. Imię to pojawiło się w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX</a> w. Uważano niekiedy, że czeskie imię <i>Zdenka</i> jest odpowiednikiem Sydonii, niemniej rozpowszechnienie tego pierwszego imienia już w <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII</a>–<a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a> i względna rzadkość Sydonii powodują, że należy zakładać, iż imion tych nie łączy ze sobą związek.", "Sancja": "<b>Sancja</b>, również <b>Sanczia</b> lub <b>Sancza</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od słowa <i>sancta</i> oznaczającego „święta”. Patronką tego imienia jest m.in. bł. <a href=\"https://pl.wikipedia.org/wiki/Sancja_Szymkowiak\" target=\"_blank\" rel=\"noopener noreferrer\">Sancja Szymkowiak</a>, zakonnica, zm. w 1942 r.", "Sonata": "<b>Sonata</b> – instrumentalna <a href=\"https://pl.wikipedia.org/wiki/Forma_muzyczna\" target=\"_blank\" rel=\"noopener noreferrer\">forma</a> cykliczna.", "Śnieżana": "<b>Śnieżka</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Ma ono związek z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">serbsko-chorwackim</a> imieniem Sniega, które stanowiło dwuczłonowe imię złożone z członu <i>S-</i> i <i>-niega</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Dobroniega\" target=\"_blank\" rel=\"noopener noreferrer\">Dobroniega</a>.", "Sebastiana": "<b>Sebastiana</b> – forma żeńska <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Sebastian_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian</a>. Patronką tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Sebastiana_z_Heraklei\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastiana</a> z <a href=\"https://pl.wikipedia.org/wiki/Heraklea_Pontyjska\" target=\"_blank\" rel=\"noopener noreferrer\">Heraklei</a> (z Tracji).", "Sefora": "Była jedną z siedmiu córek <a href=\"https://pl.wikipedia.org/wiki/Midianici\" target=\"_blank\" rel=\"noopener noreferrer\">madianickiego</a> kapłana <a href=\"https://pl.wikipedia.org/wiki/Jetro\" target=\"_blank\" rel=\"noopener noreferrer\">Jetry</a>. Po zabójstwie Egipcjanina Mojżesz uciekł do kraju Madianitów, zatrzymał się przy studni, do której właśnie udawały się napoić owce córki Jetry. Kiedy inni pasterze próbowali je przepędzić, Mojżesz stanął w ich obronie. Jetro dowiedział się o zajściu i zaprosił Mojżesza do swojego domu. Ten zamieszkał u niego i poślubił Seforę, która dała mu syna imieniem <a href=\"https://pl.wikipedia.org/wiki/Gerszom\" target=\"_blank\" rel=\"noopener noreferrer\">Gerszom</a> (Wj 2,16-22). <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Wyj%C5%9Bcia\" target=\"_blank\" rel=\"noopener noreferrer\">Księga Wyjścia</a> wzmiankuje później również o ich drugim potomku, <a href=\"https://pl.wikipedia.org/wiki/Eliezer_(syn_Moj%C5%BCesza)\" target=\"_blank\" rel=\"noopener noreferrer\">Eliezerze</a> (Wj 18,4).", "Sybille": "<b>Sybilla</b>, <b>Sibylla</b> (mitologia grecka) – <a href=\"https://pl.wikipedia.org/wiki/Wieszcz\" target=\"_blank\" rel=\"noopener noreferrer\">wieszczka</a> przepowiadająca przyszłość. Początkowo istniała jedna Sybilla, później jednak ich liczba zwiększyła się do ok. 10. Najbardziej czczoną Sybillą była wieszczka z <a href=\"https://pl.wikipedia.org/wiki/Erythraj\" target=\"_blank\" rel=\"noopener noreferrer\">Erytrei</a> utożsamiana z sybillą z <a href=\"https://pl.wikipedia.org/wiki/Cumae\" target=\"_blank\" rel=\"noopener noreferrer\">Cumae</a> – <a href=\"https://pl.wikipedia.org/wiki/Sybilla_Kuma%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Sybillą Kumańską</a> (od niej miały pochodzić <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99gi_sybilli%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">księgi sybillińskie</a>).", "Salwa": "<b>Salwa</b> – jednoczesny wystrzał z wielu sztuk <a href=\"https://pl.wikipedia.org/wiki/Bro%C5%84_palna\" target=\"_blank\" rel=\"noopener noreferrer\">broni palnej</a>. Strzelanie salwami pozwalało zrekompensować niską szybkostrzelność broni, poprzez wypuszczenie wielu <a href=\"https://pl.wikipedia.org/wiki/Pocisk\" target=\"_blank\" rel=\"noopener noreferrer\">pocisków</a> naraz, zwiększające prawdopodobieństwo rażenia celu. Było zwłaszcza elementem taktyki piechoty używającej <a href=\"https://pl.wikipedia.org/wiki/Bro%C5%84_odprzodowa\" target=\"_blank\" rel=\"noopener noreferrer\">broni odprzodowej</a> (np. <a href=\"https://pl.wikipedia.org/wiki/Kontrmarsz\" target=\"_blank\" rel=\"noopener noreferrer\">kontrmarsz</a>). Strzelanie salwami, przede wszystkim <a href=\"https://pl.wikipedia.org/wiki/Salwa_burtowa\" target=\"_blank\" rel=\"noopener noreferrer\">salwami burtowymi</a>, było także częste w czasie starć <a href=\"https://pl.wikipedia.org/wiki/Okr%C4%99t\" target=\"_blank\" rel=\"noopener noreferrer\">okrętów</a> na morzu od wieku <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII</a> aż do połowy wieku <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX</a>, kiedy to <a href=\"https://pl.wikipedia.org/wiki/Artyleria\" target=\"_blank\" rel=\"noopener noreferrer\">artyleria</a> w tego typu starciach straciła na znaczeniu na rzecz <a href=\"https://pl.wikipedia.org/wiki/Pocisk_rakietowy\" target=\"_blank\" rel=\"noopener noreferrer\">broni rakietowej</a>. W przypadku <a href=\"https://pl.wikipedia.org/wiki/Okr%C4%99t\" target=\"_blank\" rel=\"noopener noreferrer\">okrętów</a> strzelanie salwami pozwalało ponadto obserwować miejsce upadku pocisków, w celu korekt celowania.", "Sobiesława": "<b>Sobiesława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Sobie-</i> i <i>-sława</i> (\"sława\"). Oznacza \"zachowująca sławę dla siebie\" lub \"zapracowująca na sławę dla siebie\". Imię w źródłach polskich poświadczone od XIII wieku (1265 rok).", "Sybilia": "<b>Sybilla</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>; w mitologii greckiej <a href=\"https://pl.wikipedia.org/wiki/Sybilla_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">wieszczka</a> przepowiadająca przyszłość.", "Saraswati": "<b>Saraswati</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryt</a>: सरस्वती) – jest jedną z trzech najważniejszych bogiń w świecie <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduizmu</a>; imiona pozostałych to <a href=\"https://pl.wikipedia.org/wiki/Lakszmi\" target=\"_blank\" rel=\"noopener noreferrer\">Lakszmi</a> i <a href=\"https://pl.wikipedia.org/wiki/Parwati\" target=\"_blank\" rel=\"noopener noreferrer\">Parwati</a> – tworzą one „trójpostaciowość” bogiń (<i><a href=\"https://pl.wikipedia.org/wiki/Tridewi\" target=\"_blank\" rel=\"noopener noreferrer\">Tridewi</a></i>), stanowiąc niejako odpowiedź na męską <i>Trimurti</i>, złożoną z <a href=\"https://pl.wikipedia.org/wiki/Brahma\" target=\"_blank\" rel=\"noopener noreferrer\">Brahmy</a>, <a href=\"https://pl.wikipedia.org/wiki/Wisznu\" target=\"_blank\" rel=\"noopener noreferrer\">Wisznu</a> i <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aiwa\" target=\"_blank\" rel=\"noopener noreferrer\">Sziwy</a>. Według <a href=\"https://pl.wikipedia.org/wiki/Lista_postaci_z_mitologii_indyjskiej\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii indyjskiej</a> małżonka Boga-<a href=\"https://pl.wikipedia.org/wiki/Demiurg\" target=\"_blank\" rel=\"noopener noreferrer\">demiurga</a> <a href=\"https://pl.wikipedia.org/wiki/Brahma\" target=\"_blank\" rel=\"noopener noreferrer\">Brahmy</a>. Uważana za wcielenie wiedzy; bogini prawdy, mądrości i przebaczenia, patronka nauk, <a href=\"https://pl.wikipedia.org/wiki/Sztuka_indyjska\" target=\"_blank\" rel=\"noopener noreferrer\">sztuk pięknych</a>, muzyki oraz (pierwotnie) rzek. Miała przemieszczać się po wodzie na grzbiecie <a href=\"https://pl.wikipedia.org/wiki/Cygnini\" target=\"_blank\" rel=\"noopener noreferrer\">łabędzia</a>. Innym zwierzęciem utożsamianym z Saraswati jest jeden z symboli <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">Indii</a> – <a href=\"https://pl.wikipedia.org/wiki/Paw_indyjski\" target=\"_blank\" rel=\"noopener noreferrer\">paw</a>. Jej imieniem nazwano wyschniętą obecnie <a href=\"https://pl.wikipedia.org/wiki/Saraswati_(rzeka)\" target=\"_blank\" rel=\"noopener noreferrer\">rzekę</a> w <a href=\"https://pl.wikipedia.org/wiki/Podzia%C5%82_administracyjny_Indii\" target=\"_blank\" rel=\"noopener noreferrer\">stanie</a> <a href=\"https://pl.wikipedia.org/wiki/Gud%C5%BAarat\" target=\"_blank\" rel=\"noopener noreferrer\">Gujarat</a>.", "Światosława": "<b>Świętosława</b>, <b>Święcsława</b>, <b>Święsława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie. Złożone jest z członu <i>Święto-</i> („święty”, „silny, mocny”) i <i>-sława</i> („sława”). Może oznaczać: „ta, której sława jest mocna”.", "Szymona": "<b>Szymona</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i><b>שמעון</b></i> <i>Szim'eon</i> – \"<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Bóg</a> wysłuchał\") – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Szymon\" target=\"_blank\" rel=\"noopener noreferrer\">Szymon</a>, pochodzenia biblijnego. Innym, bardziej rozpowszechnionym w Polsce żeńskim odpowiednikiem imienia Szymon jest <a href=\"https://pl.wikipedia.org/wiki/Ksymena\" target=\"_blank\" rel=\"noopener noreferrer\">Ksymena</a>, zapośredniczona przez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">język hiszpański</a>.", "Sayaka": "<b>Sayaka</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さやか, サヤカ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Seren": "<b>Seren</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od słowa oznaczającego „czysty, spokojny, pogodny”. Patronem tego imienia jest św. Seren, męczennik (<a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wiek</a>).", "Safiye": "<b>Safiye</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/1550\" target=\"_blank\" rel=\"noopener noreferrer\">1550</a> na <a href=\"https://pl.wikipedia.org/wiki/Korfu\" target=\"_blank\" rel=\"noopener noreferrer\">Korfu</a> lub Rezi, zm. <a href=\"https://pl.wikipedia.org/wiki/1619\" target=\"_blank\" rel=\"noopener noreferrer\">1619</a> w <a href=\"https://pl.wikipedia.org/wiki/Stambu%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Stambule</a>) – niewolnica weneckiego lub albańskiego pochodzenia, konkubina sułtana <a href=\"https://pl.wikipedia.org/wiki/Murad_III\" target=\"_blank\" rel=\"noopener noreferrer\">Murada III</a>, matka sułtana <a href=\"https://pl.wikipedia.org/wiki/Mehmed_III\" target=\"_blank\" rel=\"noopener noreferrer\">Mehmeda III</a>. Pełny tytuł: <i>Devletlu İsmetlu Haseki Safiye Valide Sultan Aliyyetu'ş-Şan Hazretleri</i>.", "Sławomiła": "<b>Sławomiła</b> – współczesne <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię żeńskie</a> (nienotowane w dawnych źródłach) złożone z członów Sław- (\"sława\") i -mił (\"miła\", \"miłująca\").", "Shantel": "<b>Shantel</b>, właśc. <b>Stefan Hantel</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/2_marca\" target=\"_blank\" rel=\"noopener noreferrer\">2 marca</a> <a href=\"https://pl.wikipedia.org/wiki/1968\" target=\"_blank\" rel=\"noopener noreferrer\">1968</a> w <a href=\"https://pl.wikipedia.org/wiki/Mannheim\" target=\"_blank\" rel=\"noopener noreferrer\">Mannheim</a>) – niemiecki <a href=\"https://pl.wikipedia.org/wiki/DJ\" target=\"_blank\" rel=\"noopener noreferrer\">DJ</a> i <a href=\"https://pl.wikipedia.org/wiki/Producent_muzyczny\" target=\"_blank\" rel=\"noopener noreferrer\">producent muzyczny</a> wywodzący się z rodziny pochodzącej z <a href=\"https://pl.wikipedia.org/wiki/Bukowina_p%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">północnej Bukowiny</a>.", "Sinéad": "<b>Joanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Jan\" target=\"_blank\" rel=\"noopener noreferrer\">Jan</a> pochodzącego z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języka hebrajskiego</a>: Jo-hanan – „<a href=\"https://pl.wikipedia.org/wiki/Tetragram\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> jest łaskawy”.", "Shiho": "<b>Shiho</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;しほ, シホ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Sayuri": "<b>Sayuri</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さゆり, サユリ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Sumi": "Nowa koreańska szkoła była więc odpowiednikiem chińskiej tradycji <a href=\"https://pl.wikipedia.org/wiki/Caodong\" target=\"_blank\" rel=\"noopener noreferrer\">caodong</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_korea%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">kor.</a> chodong). Była to jedyna szkoła z dziewięciu, która nie pochodziła od mistrzów szkoły <a href=\"https://pl.wikipedia.org/wiki/Hongzhou_zong\" target=\"_blank\" rel=\"noopener noreferrer\">hongzhou</a>, czyli uczniów <a href=\"https://pl.wikipedia.org/wiki/Mazu_Daoyi\" target=\"_blank\" rel=\"noopener noreferrer\">Mazu Daoyi</a>.", "Sachiko": "<b>Sachiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さちこ, サチコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Sumire": "<b>Sumire</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;すみれ, スミレ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Sotera": "<b>Sotera</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, wywodzące się od słowa <i>σωτηρια (soteria)</i> – \"zbawienie\". Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Soter\" target=\"_blank\" rel=\"noopener noreferrer\">Soter</a>. Jego patronką jest św. Sotera, zm. w <a href=\"https://pl.wikipedia.org/wiki/304\" target=\"_blank\" rel=\"noopener noreferrer\">304</a> roku.", "Sewera": "<b>Sewera</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od słowa <i>severa</i> - \"surowa, poważna\". Patronką tego imienia jest św. Sewera z <a href=\"https://pl.wikipedia.org/wiki/Trewir\" target=\"_blank\" rel=\"noopener noreferrer\">Trewiru</a>, żyjąca w <a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII wieku</a>.", "Satoko": "<b>Satoko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さとこ, サトコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Satomi": "<b>Satomi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さとみ, サトミ ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, jest także używane jako nazwisko.", "Sahara": "W źródłach pojawiają się różne informacje dotyczące powierzchni pustyni. Ocenia się, że powierzchnia Sahary wynosi 7 mln, 8,6 mln lub 9,2 mln <a href=\"https://pl.wikipedia.org/wiki/Kilometr_kwadratowy\" target=\"_blank\" rel=\"noopener noreferrer\">km²</a> powierzchni.", "Sigrun": "Sigrun, mimo rodzinnej tragedii, wyszła za Helgiego i urodziła mu synów (oznacza to, że przestała być walkirią). Jej szczęście nie trwało jednak długo, gdyż Helgi zginął z ręki <a href=\"https://pl.wikipedia.org/wiki/Daga\" target=\"_blank\" rel=\"noopener noreferrer\">Daga</a> wypełniającego – wbrew złożonej ongiś przysiędze wierności – obowiązek rodowej zemsty. Oszalała z rozpaczy Sigrun nie tylko rzuciła na brata-mściciela straszliwą i nieodwołalną klątwę, ale nawet zaczęła myśleć o samobójstwie. Któregoś dnia służąca przyniosła jej prośbę Helgiego o spotkanie w kopcu grobowym i małżonkowie spędzili ze sobą noc pełną wspomnień i miłości. Cud ten, mimo nadziei Sigrun, nie powtórzył się więcej i nieszczęsna umarła wkrótce z żalu i tęsknoty. Opowiadano jednak, że Helgi i Sigrun urodzili się po raz drugi (w istocie dla niej były to trzecie narodziny): on jako Helgi Haddingjaskati, ona – jako walkiria Kara, córka Halfdana.", "Sóley": "<b>Sóley Stefánsdóttir</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/20_pa%C5%BAdziernika\" target=\"_blank\" rel=\"noopener noreferrer\">20 października</a> <a href=\"https://pl.wikipedia.org/wiki/1986\" target=\"_blank\" rel=\"noopener noreferrer\">1986</a> w <a href=\"https://pl.wikipedia.org/wiki/Reykjav%C3%ADk\" target=\"_blank\" rel=\"noopener noreferrer\">Reykjavíku</a>), znana również jako <b>Sóley</b> – pochodząca z <a href=\"https://pl.wikipedia.org/wiki/Islandia\" target=\"_blank\" rel=\"noopener noreferrer\">Islandii</a> piosenkarka, pianistka, autorka tekstów oraz członkini zespołu indie-folk <a href=\"https://pl.wikipedia.org/wiki/Seabear\" target=\"_blank\" rel=\"noopener noreferrer\">Seabear</a>. W 2010 roku wydała zawierający sześć utworów album <a href=\"https://pl.wikipedia.org/wiki/EP\" target=\"_blank\" rel=\"noopener noreferrer\">EP</a> <i>Theater Island</i>, który poprzedzał wydanie jej debiutanckiego albumu <i>We Sink</i>.", "Szoszana": "<b>Zuzanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שׁוֹשַׁנָּה&#8206; (<i>szoszana</i>), zapożyczonego przez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">język grecki</a>, a pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שׁוֹשָׁן&#8206; (<i>szoszan</i>), oznaczającego „lilia”, co z kolei prawdopodobnie wywodziło się od egipskiego <i>seszen</i>, czyli „lotos”. W Polsce imię to jest notowane w dokumentach od 1265 roku, w formach Zuzanna/Żużanna, a także pochodnych: Zanna/Żanna, Zanka/Zańka, Ożanka (zob. też <a href=\"https://pl.wikipedia.org/wiki/O%C5%BCanna_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Ożanna</a>), Zużka, Zuchna, Oszka. Wśród imion nadawanych nowo narodzonym dzieciom, Zuzanna w 2017 zajmowała 2. miejsce w grupie imion żeńskich.", "Shizuka": "<b>Shizuka</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;しずか, シズカ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone głównie przez kobiety, rzadko noszone przez mężczyzn.", "Samaya": "<b>Samaja</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">skt.</a> <i>sam</i> – razem + <i>aja</i> – iść; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tybeta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">tyb.</a> <i>dam tsig</i>), termin dosłownie tłumaczony jako obietnica, choć może mieć również inne znaczenia, takie jak porozumienie, zaangażowanie, wskazanie, ograniczenie.", "Szaron": "<b>Szaron</b>, <b>Sharon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׁרוֹן) – hebrajskie imię stosowane dla obu płci, które oznacza dosłownie <i>żyzną równinę</i>.", "Shiori": "<b>Shiori</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;しおり, シオリ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Shalu": "Populacja dzielnicy Shalu w 2016 roku liczyła 91&#160;338 mieszkańców – 45&#160;158 kobiet i 46&#160;180 mężczyzn. Liczba gospodarstw domowych wynosiła 28&#160;835, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,17 osób.", "Semiramida": "Imię Semiramida nadal jest popularne na obszarze Bliskiego Wschodu.", "Sea": "Nazwa jednostki wymawiana jest bardzo podobnie do arabskiego słowa ṣāʿ (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;صاع&#8206;), które w <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskiej</a> <a href=\"https://pl.wikipedia.org/wiki/Jurysprudencja\" target=\"_blank\" rel=\"noopener noreferrer\">jurysprudencji</a> również oznacza jednostkę objętości, określaną na podstawie <a href=\"https://pl.wikipedia.org/wiki/Hadis\" target=\"_blank\" rel=\"noopener noreferrer\">hadisów</a> na 2430 <a href=\"https://pl.wikipedia.org/wiki/Centymetr_sze%C5%9Bcienny\" target=\"_blank\" rel=\"noopener noreferrer\">ml</a> do 2512 ml, jest więc znacznie mniejsza od sea.", "Senta": "<b>Senta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> głównej bohaterki <a href=\"https://pl.wikipedia.org/wiki/Lataj%C4%85cy_Holender_(opera)\" target=\"_blank\" rel=\"noopener noreferrer\">opery <i>Latający Holender</i></a> (1843) <a href=\"https://pl.wikipedia.org/wiki/Richard_Wagner\" target=\"_blank\" rel=\"noopener noreferrer\">Richarda Wagnera</a>. Od 1860 zaczęto je nadawać w <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">Niemczech</a>.", "Siara": "Siara jest pierwszym pokarmem każdego nowo narodzonego ssaka, w tym noworodków człowieka. Unikalny skład <i>colostrum</i> ma fundamentalne znaczenie we wczesnym karmieniu potomka. W porównaniu do <a href=\"https://pl.wikipedia.org/wiki/Mleko\" target=\"_blank\" rel=\"noopener noreferrer\">mleka</a> właściwego <a href=\"https://pl.wikipedia.org/wiki/Matka\" target=\"_blank\" rel=\"noopener noreferrer\">matki</a>, siara jest szczególnie bogata w <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82ka\" target=\"_blank\" rel=\"noopener noreferrer\">białka</a>, z których większość jest mało odżywcza, ale gra ważną rolę w dojrzewaniu <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_pokarmowy\" target=\"_blank\" rel=\"noopener noreferrer\">przewodu pokarmowego</a> młodych ssaków. Zawiera dużo witaminy A, sodu i <a href=\"https://pl.wikipedia.org/wiki/Chlorki\" target=\"_blank\" rel=\"noopener noreferrer\">chlorków</a>, a stosunkowo niewiele węglowodanów, potasu i tłuszczu w porównaniu z mlekiem.", "Senna": "<i><b>Senna</b></i> – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin należący do rodziny <a href=\"https://pl.wikipedia.org/wiki/Bobowate\" target=\"_blank\" rel=\"noopener noreferrer\">bobowatych</a> (<i>Fabaceae</i>) z podrodziny <a href=\"https://pl.wikipedia.org/wiki/Brezylkowe\" target=\"_blank\" rel=\"noopener noreferrer\">brezylkowych</a> (<i>Caesalpinioideae</i>). Obejmuje ok. 280–300 gatunków. Występują w całej <a href=\"https://pl.wikipedia.org/wiki/Strefa_mi%C4%99dzyzwrotnikowa\" target=\"_blank\" rel=\"noopener noreferrer\">strefie międzyzwrotnikowej</a>, a nieliczne gatunki rosną także w <a href=\"https://pl.wikipedia.org/wiki/Strefy_umiarkowane\" target=\"_blank\" rel=\"noopener noreferrer\">strefach umiarkowanych</a>. <a href=\"https://pl.wikipedia.org/wiki/Zasi%C4%99g_(biogeografia)\" target=\"_blank\" rel=\"noopener noreferrer\">Zasięg</a> rodzaju obejmuje całą <a href=\"https://pl.wikipedia.org/wiki/Ameryka_Po%C5%82udniowa\" target=\"_blank\" rel=\"noopener noreferrer\">Amerykę Południową</a>, <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afrykę</a> i <a href=\"https://pl.wikipedia.org/wiki/Australia\" target=\"_blank\" rel=\"noopener noreferrer\">Australię</a> oraz południową część <a href=\"https://pl.wikipedia.org/wiki/Ameryka_P%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Północnej</a> i <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">Azji</a>. Rodzaj najbardziej zróżnicowany jest na kontynentach amerykańskich, gdzie obecnych jest 206 gatunków. W Australii obecne są 33 gatunki, w Afryce kontynentalnej 20, na <a href=\"https://pl.wikipedia.org/wiki/Madagaskar\" target=\"_blank\" rel=\"noopener noreferrer\">Madagaskarze</a> 9, w Azji południowej występują pojedyncze gatunki. Rośliny te rosną głównie w suchych formacjach zaroślowych i leśnych, na <a href=\"https://pl.wikipedia.org/wiki/Sawanna\" target=\"_blank\" rel=\"noopener noreferrer\">sawannach</a>, w <a href=\"https://pl.wikipedia.org/wiki/Caatinga\" target=\"_blank\" rel=\"noopener noreferrer\">caatindze</a>, <a href=\"https://pl.wikipedia.org/wiki/Cerrado\" target=\"_blank\" rel=\"noopener noreferrer\">cerrado</a>, w formacjach nadbrzeżnych, nieliczne występują w <a href=\"https://pl.wikipedia.org/wiki/Wilgotny_las_r%C3%B3wnikowy\" target=\"_blank\" rel=\"noopener noreferrer\">wilgotnych lasach równikowych</a>. Liczne gatunki zostały rozprzestrzenione poza pierwotnym zasięgiem i stały się uciążliwymi <a href=\"https://pl.wikipedia.org/wiki/Gatunek_inwazyjny\" target=\"_blank\" rel=\"noopener noreferrer\">gatunkami inwazyjnymi</a>.", "Sawanna": "<b>Sawanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Formacje_trawiaste\" target=\"_blank\" rel=\"noopener noreferrer\">formacja trawiasta</a> <a href=\"https://pl.wikipedia.org/wiki/Strefa_mi%C4%99dzyzwrotnikowa\" target=\"_blank\" rel=\"noopener noreferrer\">strefy międzyzwrotnikowej</a> o <a href=\"https://pl.wikipedia.org/wiki/Klimat\" target=\"_blank\" rel=\"noopener noreferrer\">klimacie</a> gorącym, z wyraźnie zaznaczonymi 3 porami roku, tj. <a href=\"https://pl.wikipedia.org/wiki/Pora_deszczowa\" target=\"_blank\" rel=\"noopener noreferrer\">deszczową</a> (ze średnią temperaturą 18–24&#160;°C) oraz dwiema <a href=\"https://pl.wikipedia.org/wiki/Pora_sucha\" target=\"_blank\" rel=\"noopener noreferrer\">porami suchymi</a>: chłodną (średnio 14–20&#160;°C) i gorącą (26–30&#160;°C, niekiedy nawet do 45&#160;°C). Sawanny bywają wykorzystywane jako naturalne <a href=\"https://pl.wikipedia.org/wiki/Pastwisko\" target=\"_blank\" rel=\"noopener noreferrer\">pastwiska</a>. Fauna zamieszkująca tę formację to głównie <a href=\"https://pl.wikipedia.org/wiki/Fitofag\" target=\"_blank\" rel=\"noopener noreferrer\">roślinożercy</a> żyjący w bardzo licznych stadach.", "Saria": "<b>Saria</b> (<a href=\"https://pl.wikipedia.org/wiki/Alfabet_deseret\" target=\"_blank\" rel=\"noopener noreferrer\">deseret</a> 𐐝𐐁𐐡𐐌𐐂) – imię żeńskie występujące w wyznaniach należących do <a href=\"https://pl.wikipedia.org/wiki/Ruch_%C5%9Bwi%C4%99tych_w_dniach_ostatnich\" target=\"_blank\" rel=\"noopener noreferrer\">ruchu świętych w dniach ostatnich</a> (mormonów).", "Samboja": "<b>Samboja</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członu <i>Sam-</i> (\"samotna, jedyna\") oraz członu <i>-boj-a</i> (\"bicie, walka\"). Oznacza \"tę, która walczy samotnie\".", "Shihan": "<b>Shihan</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;師範) – <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">japońskie</a> słowo oznaczające: (1) instruktora, nauczyciela, trenera; (2) tytuł honorowy nauczyciela modelowego lub „nauczyciela wyznaczającego standardy”, przyznawany certyfikatem licencyjnym w japońskich sztukach walki (<a href=\"https://pl.wikipedia.org/wiki/Bud%C5%8D\" target=\"_blank\" rel=\"noopener noreferrer\">budō</a>) instruktorom poziomu mistrzowskiego.", "Strzeżysława": "<b>Strzeżysława</b>, <b>Strzesława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członu <i>Strzeży-</i> („strzec”) oraz członu <i>-sława</i> („sława”). Oznacza „tę, która strzeże sławy”. W źródłach poświadczone w XII wieku.", "Szebora": "Wszebora po raz pierwszy została odnotowana w dokumentach w <a href=\"https://pl.wikipedia.org/wiki/1409\" target=\"_blank\" rel=\"noopener noreferrer\">1409</a>, forma Świebora – w <a href=\"https://pl.wikipedia.org/wiki/1442\" target=\"_blank\" rel=\"noopener noreferrer\">1442</a>, zaś Szabora||Siabora – w <a href=\"https://pl.wikipedia.org/wiki/1443\" target=\"_blank\" rel=\"noopener noreferrer\">1443</a>. Zdrobnieniem od tego imienia mogła być Świechna.", "Sasikala": "<b>Vivekanandan Krishnaveni Sasikala</b>, znana częściej jako <b>Sasikala</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tamilski\" target=\"_blank\" rel=\"noopener noreferrer\">tamil.</a>&#160;சசிகலா; ur. <a href=\"https://pl.wikipedia.org/wiki/18_sierpnia\" target=\"_blank\" rel=\"noopener noreferrer\">18 sierpnia</a> <a href=\"https://pl.wikipedia.org/wiki/1957\" target=\"_blank\" rel=\"noopener noreferrer\">1957</a> w Thiruthuraipoondi) – <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjska</a> polityk. Pochodzi ze społeczności Thevarów. Wpływy zawdzięcza bliskiej relacji z <a href=\"https://pl.wikipedia.org/wiki/Jayaram_Jayalalitha\" target=\"_blank\" rel=\"noopener noreferrer\">Jayalalithą</a>, której powierniczką była na przestrzeni kilku dekad. Zaangażowała się w działalność <a href=\"https://pl.wikipedia.org/wiki/Og%C3%B3lnoindyjska_Partia_Ludu_Drawid%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Ogólnoindyjskiej Partii Ludu Drawidów</a> (AIADMK), odegrała istotną, zakulisową rolę w kryzysie sukcesyjnym po śmierci <a href=\"https://pl.wikipedia.org/wiki/M.G._Ramachandran\" target=\"_blank\" rel=\"noopener noreferrer\">M.G. Ramachandrana</a>. Uwikłana w liczne skandale korupcyjne, zbudowała rozległe imperium biznesowe. Po śmierci Jayalalithy jedna z głównych postaci walczących o kontrolę nad AIADMK, sekretarz generalna partii (2016–2017). Pozbawiona partyjnego członkostwa, od 2017 do 2021 odbywała karę pozbawienia wolności za korupcję w więzieniu w Bengaluru. Zaangażowała się w działalność ugrupowania Amma Makkal Munnetra Kazhagam (AMMK), podjęła też działania celem odzyskania kontroli nad AIADMK. Uwieczniona w indyjskiej <a href=\"https://pl.wikipedia.org/wiki/Kultura_popularna\" target=\"_blank\" rel=\"noopener noreferrer\">kulturze popularnej</a>, przez zwolenników określana mianem <i>chinnammy</i> (małej mateczki), wykorzystuje też tytuł <i>Puratchi Thai</i> (rewolucyjnej matki).", "Satsuki": "<b>Satsuki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さつき, サツキ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a> rzadko noszone przez mężczyzn, używane także jako nazwisko.", "Shinobu": "<b>Shinobu</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;しのぶ, シノブ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">japońskie imię</a> używane zarówno przez mężczyzn, jak i kobiety.", "Světlana": "Organizacja powstała we wrześniu 1948 roku w <a href=\"https://pl.wikipedia.org/wiki/Zlin\" target=\"_blank\" rel=\"noopener noreferrer\">Zlinie</a>. Doszło wówczas do spotkania b. partyzantów <a href=\"https://pl.wikipedia.org/wiki/Josef_Matou%C5%A1\" target=\"_blank\" rel=\"noopener noreferrer\">Josefa Matouša</a> i Rudolfa Lenharda z towarzyszami broni z partyzantki Jaromírem Vrbą, Josefem Burešem, braćmi Aloisem i Antonínem Doležalami oraz Antonínem Slabikiem. Dwaj pierwsi byli przedstawicielami b. dowódcy partyzanckiego <a href=\"https://pl.wikipedia.org/wiki/Josef_V%C3%A1vra-Sta%C5%99%C3%ADk\" target=\"_blank\" rel=\"noopener noreferrer\">Josefa Vávry-Staříka</a>, przebywającego we <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a>. Współpracował on z francuskimi służbami specjalnymi Deuxiéme Bureau. Po początkowym poparciu dla <a href=\"https://pl.wikipedia.org/wiki/Komunizm\" target=\"_blank\" rel=\"noopener noreferrer\">komunistów</a> zraził się do ich rządów i zagrożony aresztowaniem przedostał się na Zachód, gdzie postanowił utworzyć konspiracyjną organizację antykomunistyczną złożoną z b. podkomendnych z okresu okupacji niemieckiej. Została ona nazwana \"Světlana\" od imienia córki J. Vávry-Staříka. Jednakże organizacja od samego początku znajdowała się pod kontrolą czechosłowackich służb bezpieczeństwa <a href=\"https://pl.wikipedia.org/wiki/St%C3%A1tn%C3%AD_bezpe%C4%8Dnost\" target=\"_blank\" rel=\"noopener noreferrer\">StB</a>, którzy ją zinfiltrowali. Po początkowym spokojnym okresie rozbudowywania struktur już w marcu <a href=\"https://pl.wikipedia.org/wiki/1949\" target=\"_blank\" rel=\"noopener noreferrer\">1949</a> r. rozpoczęły się aresztowania członków organizacji. Od kwietnia <a href=\"https://pl.wikipedia.org/wiki/1950\" target=\"_blank\" rel=\"noopener noreferrer\">1950</a> r. trwały procesy, na których padło 16 wyroków śmierci, dot. m.in. J. Vávry-Staříka, J. Matouša i R. Lenharda (13 wykonano). Josef Vávra-Stařík został porwany przez ŠtB i wywiezieny do <a href=\"https://pl.wikipedia.org/wiki/Praga\" target=\"_blank\" rel=\"noopener noreferrer\">Pragi</a>. W kwietniu <a href=\"https://pl.wikipedia.org/wiki/1953\" target=\"_blank\" rel=\"noopener noreferrer\">1953</a> r. skazano go na karę śmierci, wykonaną 26 sierpnia tego roku.", "Serenada": "<b>Serenada</b> – <a href=\"https://pl.wikipedia.org/wiki/Forma_muzyczna\" target=\"_blank\" rel=\"noopener noreferrer\">forma muzyczna</a>:", "Sane": "<b>Scanner Access Now Easy</b> (SANE) – <a href=\"https://pl.wikipedia.org/wiki/Wieloplatformowo%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">wieloplatformowy</a> interfejs programowania aplikacji <a href=\"https://pl.wikipedia.org/wiki/Application_Programming_Interface\" target=\"_blank\" rel=\"noopener noreferrer\">API</a>, który umożliwia dostęp do większości <a href=\"https://pl.wikipedia.org/wiki/Skaner_(czytnik)\" target=\"_blank\" rel=\"noopener noreferrer\">skanerów optycznych</a>. Interfejs Sane jest rozwijany na zasadach <a href=\"https://pl.wikipedia.org/wiki/FLOSS\" target=\"_blank\" rel=\"noopener noreferrer\">FLOSS</a>, co oznacza, że każdy może pomóc w jego tworzeniu.", "Seka": "<b>Hsekju</b> albo <b>Seka</b> – znany wyłącznie z imienia władca <a href=\"https://pl.wikipedia.org/wiki/Dolny_Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Dolnego Egiptu</a> z okresu predynastycznego (koniec IV tysiąclecia <a href=\"https://pl.wikipedia.org/wiki/P.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">p.n.e.</a>). Imię jego widnieje jako drugie z kolei (pierwsze jest nieczytelne) w najwyższej linii <a href=\"https://pl.wikipedia.org/wiki/Kamie%C5%84_z_Palermo\" target=\"_blank\" rel=\"noopener noreferrer\">kamienia z Palermo</a>, bazaltowej steli zawierającej roczniki od czasów mitycznych do <a href=\"https://pl.wikipedia.org/wiki/V_dynastia\" target=\"_blank\" rel=\"noopener noreferrer\">V dynastii</a>. Nie został potwierdzony w żadnym innym źródle. Jego panowanie jest zatem podważane – możliwe, że był jedynie postacią mityczną lub nawet całkowicie zmyśloną.", "Sonatina": "<b>Sonatina</b> – <a href=\"https://pl.wikipedia.org/wiki/Forma_muzyczna\" target=\"_blank\" rel=\"noopener noreferrer\">forma muzyczna</a>, krótka, miniaturowa <a href=\"https://pl.wikipedia.org/wiki/Sonata\" target=\"_blank\" rel=\"noopener noreferrer\">sonata</a>, zwykle przeznaczona do celów dydaktycznych.", "Sofronia": "<b>Sofronia</b> – włoskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z elementów <i>sōs</i>- (\"zdrowy\") i -<i>phron</i> (\"duch, umysł\"), oznaczające kobietę mądrą, rozumną.", "Slavomíra": "<b>Sławomira</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Sławo-</i> („sława”) i <i>-mira</i> („pokój, spokój, dobro”). Mogło oznaczać „sławiąca pokój”. Notowane w źródłach od <a href=\"https://pl.wikipedia.org/wiki/1386\" target=\"_blank\" rel=\"noopener noreferrer\">1386</a> roku, występujące także w wariantach <i><b>Sławomirz</b></i> (fem.) i <i><b>Sławomirza</b></i>. Przykładowe dawne możliwe zdrobnienia: Sławna, Sławka, Sławnica, Sławocha.", "Sergia": "<b>Sergia</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Sergiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Sergiusz</a> wywodzącego się od nazwy <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <i>Sergia</i>. Patronką imienia jest <a href=\"https://pl.wikipedia.org/wiki/Julia_Rapiej\" target=\"_blank\" rel=\"noopener noreferrer\">bł. Maria Sergia od Matki Bożej Bolesnej</a>, siostra sakramentka, wspominana razem z <a href=\"https://pl.wikipedia.org/wiki/Adela_Mardosewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Marią Stellą</a> i innymi towarzyszkami.", "Sanah": "Pseudonim „sanah” powstał po skróceniu angielskiej wersji pierwszego imienia piosenkarki – Susannah (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">po polsku</a> „Zuzanna”). Przedtem występowała pod pseudonimem „Ayreen” (po polsku „Irena”), pochodzącym od jej drugiego imienia.", "Simple": "<b>Simple SA</b> – polski producent rozwiązań informatycznych oferujący systemy <a href=\"https://pl.wikipedia.org/wiki/Planowanie_zasob%C3%B3w_przedsi%C4%99biorstwa\" target=\"_blank\" rel=\"noopener noreferrer\">ERP</a>, <a href=\"https://pl.wikipedia.org/wiki/Zarz%C4%85dzanie_relacjami_z_klientami\" target=\"_blank\" rel=\"noopener noreferrer\">CRM</a>, <a href=\"https://pl.wikipedia.org/wiki/Zarz%C4%85dzanie_procesami_biznesowymi\" target=\"_blank\" rel=\"noopener noreferrer\">BPM</a>, <a href=\"https://pl.wikipedia.org/wiki/Zarz%C4%85dzanie_zasobami_ludzkimi\" target=\"_blank\" rel=\"noopener noreferrer\">HRM</a> i <a href=\"https://pl.wikipedia.org/wiki/Business_Intelligence\" target=\"_blank\" rel=\"noopener noreferrer\">BI</a>. W latach 2000–2022 roku Simple SA była notowana na <a href=\"https://pl.wikipedia.org/wiki/Gie%C5%82da_Papier%C3%B3w_Warto%C5%9Bciowych_w_Warszawie\" target=\"_blank\" rel=\"noopener noreferrer\">Giełdzie Papierów Wartościowych w Warszawie</a>.", "Shulin": "Populacja dzielnicy Shulin w 2016 roku liczyła 184&#160;400 mieszkańców – 92&#160;336 kobiet i 92&#160;064 mężczyzn. Liczba gospodarstw domowych wynosiła 66&#160;035, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 2,79 osób.", "Ségolène": "<b>Segolena</b>, Zygolena – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, pierwotnie stanowiące spieszczoną formę <a href=\"https://pl.wikipedia.org/wiki/Zyglinda\" target=\"_blank\" rel=\"noopener noreferrer\">Zyglindy</a> (<i>Seglinde //Siglinde</i>), imienia złożonego z członów <i>sig</i> – \"zwycięstwo\" i <i>lind</i> – \"tarcza ochronna\". Patronką tego imienia jest św. Segolena (Zygolena), <a href=\"https://pl.wikipedia.org/wiki/Opat\" target=\"_blank\" rel=\"noopener noreferrer\">ksieni</a> z Troclar (w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Albi\" target=\"_blank\" rel=\"noopener noreferrer\">Albi</a>).", "Sędzisława": "<b>Sędzisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członu <i>Sędzi-</i> („sądzić”) oraz członu <i>-sława</i> („sława”). Być może oznaczało „ta, której sądzona jest sława”. Imię wystąpiło w średniowiecznych dokumentach w 1250 r., a w męskiej formie w 1211."};
